// Unit 28: Sprichwörter
// Level: B2

const UNIT_28 =
{n:28,lang:"de",srcLang:"en",track:"v2",title:"Sprichwörter",sub:"Morgenstund hat Gold im Mund",icon:"📜",level:"B2.1",color:"#7B5EE8",lessons:[
{id:"deu_r28l1",title:"Sonntagsbesuch",icon:"\u2615",xp:15,board:true,steps:[
{type:"intro",title:"Sonntagsbesuch",desc:"Enter the world of German proverbs and oral tradition. Learn core literary vocabulary. Understand why proverbs matter so much in German culture.",goals:["Learn 18 words from the literary tradition","Understand proverbs as cultural wisdom","Distinguish Sprichwort, Redewendung, and Gleichnis","Join Heinrich on his Sunday visit"]},
{type:"teach",trg:"das Sprichwort",src:"proverb",pos:"noun",gender:"n",note:"Sprich (speak) + Wort (word). A complete sentence of folk wisdom.\nDas Sprichwort. Plural: die Sprichwörter.",example:"A: Kennst du ein deutsches Sprichwort?\nB: Ja! 'Morgenstund hat Gold im Mund.'\nA: Das ist ein schönes Sprichwort.\nB: Es gibt Tausende von Sprichwörtern.",exampleSrc:"A: Do you know a German proverb?\nB: Yes! 'The early bird catches the worm.'\nA: That is a nice proverb.\nB: There are thousands of proverbs.",funFact:"Literally a 'speak-word.' German has thousands of Sprichwörter, many dating back centuries. 'Morgenstund hat Gold im Mund' is one of the oldest. A Sprichwort is always a complete sentence of wisdom."},
{type:"teach",trg:"die Redewendung",src:"idiom, figure of speech",pos:"noun",gender:"f",note:"Rede (speech) + Wendung (turn). A fixed phrase used in sentences.\nDifferent from Sprichwort: not a complete sentence of wisdom.",example:"A: Was ist eine Redewendung?\nB: Ein fester Ausdruck wie 'ins Fettnäpfchen treten.'\nA: Und ein Sprichwort?\nB: Ein ganzer Satz der Weisheit, wie 'Übung macht den Meister.'",exampleSrc:"A: What is a Redewendung?\nB: A fixed expression like 'to put your foot in it.'\nA: And a proverb?\nB: A complete sentence of wisdom, like 'Practice makes perfect.'",funFact:"Literally a 'speech-turn.' A Redewendung is a fixed phrase you use inside sentences, while a Sprichwort stands alone as a complete sentence. 'Ins Fettnäpfchen treten' is a Redewendung, not a Sprichwort."},
{type:"teach",trg:"die Weisheit",src:"wisdom",pos:"noun",gender:"f",note:"From weise (wise) + -heit (state of being). Die Weisheit.\nThe -heit suffix always creates feminine abstract nouns.",example:"A: Was tragen Sprichwörter?\nB: Alte Weisheit. Erfahrung aus Jahrhunderten.\nA: Ist jede Weisheit zeitlos?\nB: Nicht alle. Manche Weisheiten passen nicht mehr.",exampleSrc:"A: What do proverbs carry?\nB: Old wisdom. Experience from centuries.\nA: Is every piece of wisdom timeless?\nB: Not all. Some wisdom no longer fits.",funFact:"From 'weise' (wise) + '-heit' (state of being). 'Alte Weisheit' (ancient wisdom) is what Sprichwörter carry. 'Weisheitszahn' (wisdom tooth) is the bonus compound. The -heit suffix always makes feminine abstract nouns."},
{type:"teach",trg:"die Redensart",src:"expression, manner of speaking",pos:"noun",gender:"f",note:"Reden (to speak) + Art (kind/manner). Broader than Redewendung.\nAny characteristic way of expressing something.",example:"A: 'Das ist so eine Redensart' heißt was?\nB: Es bedeutet: nimm es nicht wörtlich.\nA: Also eine Art zu sprechen?\nB: Genau. Eine besondere Art, etwas auszudrücken.",exampleSrc:"A: 'That is just a Redensart' means what?\nB: It means: do not take it literally.\nA: So a way of speaking?\nB: Exactly. A particular way of expressing something.",funFact:"'Reden' (to speak) + 'Art' (kind/manner). Broader than Redewendung. Any characteristic way of expressing something. 'Das ist so eine Redensart' dismisses literal interpretation."},
{type:"teach",trg:"das Märchen",src:"fairy tale",pos:"noun",gender:"n",note:"From Maer (old word for story) + -chen (diminutive). Das Märchen.\nThe diminutive suffix makes it neuter.",example:"A: Kennst du deutsche Märchen?\nB: Ja, Rotkäppchen und Schneewittchen.\nA: Wer hat die Märchen gesammelt?\nB: Die Brüder Grimm. Im 19. Jahrhundert.",exampleSrc:"A: Do you know German fairy tales?\nB: Yes, Little Red Riding Hood and Snow White.\nA: Who collected the fairy tales?\nB: The Brothers Grimm. In the 19th century.",funFact:"The Brothers Grimm collected German Märchen and made them world-famous. The diminutive '-chen' suffix gives it neuter gender and a gentle quality. From 'Maer,' an old word for story or news."},
{type:"match",pairs:[{trg:"die Redewendung",src:"idiom, figure of speech"},{trg:"die Weisheit",src:"wisdom"},{trg:"die Redensart",src:"expression, manner of speaking"},{trg:"das Märchen",src:"fairy tale"}]},
{type:"teach",trg:"die Erzählung",src:"narrative, story",pos:"noun",gender:"f",note:"From erzählen (to narrate). More literary than Geschichte.\nA short literary work. Kurzerzählung = short story.",example:"A: Was ist der Unterschied zwischen Erzählung und Geschichte?\nB: Erzählung klingt literarischer.\nA: Also ein Fachbegriff?\nB: Ja, für kurze literarische Werke.",exampleSrc:"A: What is the difference between Erzählung and Geschichte?\nB: Erzählung sounds more literary.\nA: So a technical term?\nB: Yes, for short literary works.",funFact:"More literary than 'Geschichte' (story/history). A short literary work. 'Kurzerzählung' = short story. The formal word for narrative fiction. From 'erzählen' (to tell/narrate)."},
{type:"mc",q:"Was ist der Unterschied zwischen einem Sprichwort und einer Redewendung?",opts:["Ein Sprichwort ist ein ganzer Satz, eine Redewendung nur ein fester Ausdruck","Ein Sprichwort ist informal, eine Redewendung ist formell","Eine Redewendung ist aelter als ein Sprichwort","Es gibt keinen Unterschied"],ans:"Ein Sprichwort ist ein ganzer Satz, eine Redewendung nur ein fester Ausdruck",hint:"One is a complete sentence of wisdom that stands alone. The other is a fixed phrase used inside sentences."},
{type:"teach",trg:"die Metapher",src:"metaphor",pos:"noun",gender:"f",note:"From Greek 'metaphora' (transfer). Feminine in German.\n'Das Leben ist eine Reise' is a classic Metapher.",example:"A: Was ist eine Metapher?\nB: Ein Bild für etwas anderes.\nA: Zum Beispiel?\nB: 'Das Leben ist eine Reise.' Das Leben reist nicht wirklich.",exampleSrc:"A: What is a metaphor?\nB: An image for something else.\nA: For example?\nB: 'Life is a journey.' Life does not actually travel.",funFact:"From Greek 'metaphora' (transfer). Feminine in German, though many learners guess neuter. 'Das Leben ist eine Reise' is a classic Metapher. German literary analysis loves identifying Metaphern in texts."},
{type:"teach",trg:"das Gleichnis",src:"parable, allegory",pos:"noun",gender:"n",note:"From gleich (same/equal) + -nis (abstract noun suffix).\nBiblical parables are Gleichnisse.",example:"A: Was ist ein Gleichnis?\nB: Eine einfache Geschichte mit tieferer Bedeutung.\nA: Wie in der Bibel?\nB: Ja, aber auch Heinrichs Geschichten sind Gleichnisse.",exampleSrc:"A: What is a parable?\nB: A simple story with deeper meaning.\nA: Like in the Bible?\nB: Yes, but Heinrich's stories are also parables.",funFact:"From 'gleich' (same/equal) + '-nis' (abstract noun suffix). Biblical parables are 'Gleichnisse.' Heinrich's bakery stories are Gleichnisse: simple tales carrying deeper meaning."},
{type:"teach",trg:"der Dichter",src:"poet, literary writer",pos:"noun",gender:"m",note:"From dichten (to compose poetry). Der Dichter.\nGoethe is 'der größte deutsche Dichter.'",example:"A: Wer ist der bekannteste deutsche Dichter?\nB: Goethe. Ohne Zweifel.\nA: Was hat der Dichter geschrieben?\nB: Gedichte, Romane, Theaterstücke. Alles.",exampleSrc:"A: Who is the most famous German poet?\nB: Goethe. Without doubt.\nA: What did the poet write?\nB: Poems, novels, plays. Everything.",funFact:"'Dichter und Denker' (poets and thinkers) is how Germans describe their cultural tradition. The word covers poets and literary authors. Goethe is 'der größte deutsche Dichter' (the greatest German poet)."},
{type:"teach",trg:"die Dichterin",src:"poet, literary writer (female)",pos:"noun",gender:"f",note:"Dichter + -in. Die Dichterin.\nAnnette von Droste-Huelshoff, Ingeborg Bachmann.",example:"A: Kennst du eine deutsche Dichterin?\nB: Ingeborg Bachmann. Eine großartige Dichterin.\nA: Was hat die Dichterin geschrieben?\nB: Gedichte und Erzählungen. Wunderbare Sprache.",exampleSrc:"A: Do you know a German female poet?\nB: Ingeborg Bachmann. A magnificent poet.\nA: What did the poet write?\nB: Poems and narratives. Wonderful language.",funFact:"Annette von Droste-Huelshoff, Else Lasker-Schüler, Ingeborg Bachmann: Germany's great Dichterinnen deserve the title. The -in suffix consistently creates feminine forms for professions."},
{type:"fb",s:"Ein {1} ist eine einfache Geschichte mit tieferer Bedeutung, wie eine Parabel.",a:["Gleichnis"],opts:["Märchen","Gleichnis","Gedicht","Reim"],hint:"From 'gleich' (same/equal). A simple story that stands for something deeper. Biblical parables are examples.",sSrc:"A parable is a simple story with deeper meaning, like an allegory."}
]},
{id:"deu_r28l1b",title:"Sonntagsbesuch (Teil 2)",icon:"\u2615",xp:15,board:true,steps:[
{type:"intro",title:"Sonntagsbesuch (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"literarisch",src:"literary",pos:"adj",gender:null,note:"From Latin 'litterarius.' Literarische Werke = literary works.\n'Ein literarischer Abend' is a German cultural tradition.",example:"A: Ist das ein literarischer Text?\nB: Ja, sehr literarisch. Poetische Sprache.\nA: Was bedeutet 'literarisch' genau?\nB: Zur Literatur gehörend. Kuenstlerisch geschrieben.",exampleSrc:"A: Is that a literary text?\nB: Yes, very literary. Poetic language.\nA: What does 'literary' mean exactly?\nB: Belonging to literature. Artistically written.",funFact:"'Ein literarischer Abend' (a literary evening) is a German cultural tradition: readings, wine, and discussion. 'Literarische Werke' is the standard term for literary works. Latin root: 'litterarius.'"},
{type:"teach",trg:"poetisch",src:"poetic",pos:"adj",gender:null,note:"From Greek 'poietikos' (creative). Poetische Sprache\nuses imagery, rhythm, and metaphor.",example:"A: Das klingt sehr poetisch.\nB: Danke! Oder meinst du das ironisch?\nA: Nein, wirklich. Poetische Sprache ist schoen.\nB: Wenn sie echt ist, ja.",exampleSrc:"A: That sounds very poetic.\nB: Thanks! Or do you mean that ironically?\nA: No, really. Poetic language is beautiful.\nB: When it is genuine, yes.",funFact:"From Greek 'poietikos' (creative). 'Poetische Sprache' uses imagery, rhythm, and metaphor. 'Das klingt sehr poetisch' is both a compliment and sometimes gentle teasing."},
{type:"teach",trg:"zeitlos",src:"timeless",pos:"adj",gender:null,note:"Zeit (time) + -los (without). Timeless.\nThe -los suffix always means 'without': endlos, grenzenlos.",example:"A: Sind Sprichwörter zeitlos?\nB: Die besten schon. Sie überleben Jahrhunderte.\nA: Zeitlose Weisheit also?\nB: Genau. Sie gilt heute wie vor 500 Jahren.",exampleSrc:"A: Are proverbs timeless?\nB: The best ones, yes. They survive centuries.\nA: Timeless wisdom then?\nB: Exactly. It is valid today as it was 500 years ago.",funFact:"'Zeit' (time) + '-los' (without). Timeless. 'Zeitlose Weisheit' is what good Sprichwörter carry. They outlive the people who coined them. The -los suffix always means 'without': zeitlos, endlos, grenzenlos."},
{type:"teach",trg:"volkstümlich",src:"folk, popular, traditional",pos:"adj",gender:null,note:"Volk (people/folk) + tuemlch (characteristic of).\nCarries warmth and earthiness.",example:"A: Sind Sprichwörter volkstümlich?\nB: Ja, sie kommen vom Volk, nicht von Gelehrten.\nA: Volkstümlche Sprache ist einfach?\nB: Einfach, aber tief. Das ist die Kunst.",exampleSrc:"A: Are proverbs folk in nature?\nB: Yes, they come from ordinary people, not scholars.\nA: Folk language is simple?\nB: Simple, but deep. That is the art.",funFact:"'Volk' (people/folk) + 'tuemlch' (characteristic of). 'Volkstümlche Sprichwörter' come from ordinary people, not scholars. The word carries warmth and earthiness."},
{type:"mc",q:"Das Wort 'zeitlos' bedeutet, dass etwas...",opts:["keiner bestimmten Zeit zugeordnet ist und immer gueltig bleibt","ausschliesslich modern und aktuell ist","sehr schnell veraltet","nur in der Vergangenheit gueltig war"],ans:"keiner bestimmten Zeit zugeordnet ist und immer gueltig bleibt",hint:"The suffix -los means 'without.' Add it to the German word for 'period' and you get this concept."},
{type:"teach",trg:"überliefert",src:"handed down, transmitted",pos:"adj",gender:null,note:"Über (over) + liefert (delivered). Past participle of überliefern.\n'Mündlich überliefert' = orally transmitted.",example:"A: Wie haben Sprichwörter überlebt?\nB: Sie wurden mündlich überliefert.\nA: Von Generation zu Generation?\nB: Ja. Überlieferte Weisheit braucht kein Buch.",exampleSrc:"A: How did proverbs survive?\nB: They were handed down orally.\nA: From generation to generation?\nB: Yes. Transmitted wisdom needs no book.",funFact:"'Über' (over) + 'liefert' (delivered). Past participle of 'überliefern.' 'Mündlich überliefert' (orally transmitted) describes how proverbs survived before writing. Delivered over the generations."},
{type:"teach",trg:"erzählen",src:"to tell, to narrate",pos:"verb",gender:null,note:"Not separable. Different from sagen (to say):\nerzählen implies a story, sagen implies a statement.",example:"A: Heinrich, erzähl uns eine Geschichte!\nB: Gern. Ich erzähle euch von meinem Großvater.\nA: Er erzählt so lebendig.\nB: Ja, er ist ein geborener Erzähler.",exampleSrc:"A: Heinrich, tell us a story!\nB: Gladly. I will tell you about my grandfather.\nA: He narrates so vividly.\nB: Yes, he is a born storyteller.",funFact:"From old German 'irzellen' (to recount). Not separable. Different from 'sagen' (to say): erzählen implies a narrative with beginning, middle, and end. Sagen implies a single statement."},
{type:"teach",trg:"dichten",src:"to compose poetry, to write literary works",pos:"verb",gender:null,note:"From Latin 'dictare' (to dictate). Not separable.\nAlso colloquially: 'Das ist gedichtet!' (That is made up!).",example:"A: Goethe dichtete in Weimar.\nB: Was hat er dort gedichtet?\nA: Faust, Gedichte, alles Moegliche.\nB: Dichten ist eine Kunst.",exampleSrc:"A: Goethe composed poetry in Weimar.\nB: What did he compose there?\nA: Faust, poems, everything possible.\nB: Composing poetry is an art.",funFact:"'Goethe dichtete in Weimar.' The verb behind Dichter (poet) and Dichtung (literature). Colloquially, 'Das ist gedichtet!' means 'That is made up!' Latin root 'dictare' originally meant 'to dictate.'"},
{type:"teach",trg:"zitieren",src:"to quote",pos:"verb",gender:null,note:"From Latin 'citare' (to summon). Not separable.\nEin Zitat (a quote) is the noun.",example:"A: Darf ich Heinrich zitieren?\nB: Natürlich. Was hat er gesagt?\nA: Ich zitiere: 'Morgenstund hat Gold im Mund.'\nB: Das ist ein Klassiker. Gutes Zitat.",exampleSrc:"A: May I quote Heinrich?\nB: Of course. What did he say?\nA: I quote: 'The early bird catches the worm.'\nB: That is a classic. Good quote.",funFact:"Germans love quoting. 'Ich zitiere Heinrich' (I quote Heinrich). 'Ein Zitat' (a quote) is the noun. Not separable. Latin 'citare' originally meant 'to summon,' as if summoning someone's words to speak for you."},
{type:"fb",s:"Goethe war der größte deutsche {1}. Er schrieb Gedichte, Romane und Theaterstücke.",a:["Dichter"],opts:["Erzähler","Zitator","Autor","Dichter"],hint:"The word for a poet or literary writer. From 'dichten' (to compose poetry).",sSrc:"Goethe was the greatest German poet. He wrote poems, novels, and plays."},
{type:"mc",q:"Heinrich teilt alte Sätze mit, die Weisheit enthalten und seit Generationen weitergegeben werden. Welches deutsche Wort beschreibt das?",opts:["Gleichnis","Sprichwort","Redewendung","Märchen"],ans:"Sprichwort",hint:"A complete sentence of folk wisdom, passed down for generations. Not an expression or idiom, but a full standalone saying."},
{type:"fb",s:"Diese alte {1} hat Generationen überdauert.",a:["Weisheit"],opts:["Erzählung","Weisheit","Metapher","Redensart"],hint:"The German word for 'wisdom'. What proverbs carry from generation to generation.",sSrc:"This old wisdom has survived generations."},
{type:"mc",q:"Ein Gleichnis ist am besten beschrieben als...",opts:["eine grammatische Übungsaufgabe ohne literarische Tiefe","eine einfache Art von lyrischem Gedicht","eine Parabel oder Allegorie mit tieferer Bedeutung","ein sachlicher journalistischer Artikel"],ans:"eine Parabel oder Allegorie mit tieferer Bedeutung",hint:"From 'gleich' (same/equal). A simple story that stands for something deeper."},
{type:"mc",q:"Was bedeutet 'poetisch'?",opts:["to compose poetry, to write literary works","expression, manner of speaking","proverb","poetic"],ans:"poetic",hint:"Near-identical in English. Related to Poesie (poetry)."},
{type:"fb",s:"Sind Sprichwörter {1}?",a:["volkstümlich"],opts:["die Redensart","die Weisheit","zeitlos","volkstümlich"],hint:"From Volk (people/folk) + tümlich (typical of). An adjective meaning 'of the common people'.",sSrc:"Are proverbs folk in nature?"},
{type:"mc",q:"Was bedeutet 'überliefert'?",opts:["handed down, transmitted","to compose poetry, to write literary works","to tell, to narrate","proverb"],ans:"handed down, transmitted",hint:"über (over) + liefern (to deliver). Delivered over generations."},
{type:"fb",s:"Wie sagt man 'to tell, to narrate' auf Deutsch? {1}",a:["erzählen"],opts:["die Metapher","dichten","erzählen","überliefert"],hint:"The everyday verb for telling stories. Related to Erzählung (narrative).",sSrc:"How do you say 'to tell, to narrate' in German?"},
{type:"mc",q:"Was bedeutet 'dichten'?",opts:["handed down, transmitted","to compose poetry, to write literary works","metaphor","wisdom"],ans:"to compose poetry, to write literary works",hint:"The verb form of Dichter. Composing something that belongs to belles-lettres."},
{type:"fb",s:"Darf ich Heinrich {1}?",a:["zitieren"],opts:["die Weisheit","die Erzählung","literarisch","zitieren"],hint:"Cognate of English 'cite'. The verb for repeating someone's exact words.",sSrc:"May I quote Heinrich?"}
]},
{id:"deu_r28l2",title:"Dichtung und Wahrheit",icon:"\ud83d\udcda",xp:15,board:true,steps:[
{type:"intro",title:"Dichtung und Wahrheit",desc:"Learn the words of German literature. From poems and novels to epochs and genres. Master the vocabulary of the literary tradition.",goals:["Learn 20 words for literary genres and forms","Understand the three genres of literature","Describe poems, stories, and novels in German","Expand your literary vocabulary"]},
{type:"teach",trg:"das Gedicht",src:"poem",pos:"noun",gender:"n",note:"From dichten (to compose). Das Gedicht. Neuter because of Ge- prefix.\n'Ein Gedicht aufsagen' = to recite a poem.",example:"A: Kennst du ein deutsches Gedicht?\nB: Ja, 'Der Erlkoenig' von Goethe.\nA: Kannst du das Gedicht aufsagen?\nB: Den Anfang schon. Es ist sehr bekannt.",exampleSrc:"A: Do you know a German poem?\nB: Yes, 'The Erlking' by Goethe.\nA: Can you recite the poem?\nB: The beginning, yes. It is very well known.",funFact:"Neuter because of the Ge- prefix. 'Ein Gedicht aufsagen' (to recite a poem) is a German school tradition. Schiller's 'Die Buergschaft' is the classic recitation piece."},
{type:"teach",trg:"der Vers",src:"verse, line of poetry",pos:"noun",gender:"m",note:"From Latin 'versus' (a turning, a line). Der Vers.\nEach line in a poem is a Vers.",example:"A: Wie viele Verse hat das Gedicht?\nB: Zwoelf Verse in drei Strophen.\nA: Der erste Vers ist am schoensten.\nB: Ja, er setzt den Ton für das ganze Gedicht.",exampleSrc:"A: How many verses does the poem have?\nB: Twelve verses in three stanzas.\nA: The first verse is the most beautiful.\nB: Yes, it sets the tone for the whole poem.",funFact:"In German poetry, each line is a Vers. 'Freie Verse' (free verse) has no rhyme or fixed meter. 'Der erste Vers' sets the tone. Latin 'versus' literally meant 'a turning,' as the poet turns to a new line."},
{type:"teach",trg:"die Strophe",src:"stanza",pos:"noun",gender:"f",note:"From Greek 'strophe' (turning). A group of Verse forming a unit.\nGerman poetry analysis always counts Strophen.",example:"A: Wie viele Strophen hat das Gedicht?\nB: Vier Strophen mit je vier Versen.\nA: Die letzte Strophe ist die stärkste.\nB: Ja, dort kommt die Wendung.",exampleSrc:"A: How many stanzas does the poem have?\nB: Four stanzas with four verses each.\nA: The last stanza is the strongest.\nB: Yes, that is where the turning point comes.",funFact:"From Greek 'strophe' (turning). A group of Verse forming a unit. 'Die erste Strophe' (the first stanza). German poetry analysis always counts Strophen and Verse."},
{type:"teach",trg:"der Reim",src:"rhyme",pos:"noun",gender:"m",note:"From Old French 'rime.' Der Reim.\n'Sich einen Reim auf etwas machen' = to make sense of something.",example:"A: Reimen sich diese Wörter?\nB: Ja, 'Haus' und 'Maus' sind ein Reim.\nA: Kinder lernen durch Reime.\nB: Ja, Abzaehlreime und Kinderlieder.",exampleSrc:"A: Do these words rhyme?\nB: Yes, 'Haus' and 'Maus' are a rhyme.\nA: Children learn through rhymes.\nB: Yes, counting rhymes and children's songs.",funFact:"From Old French 'rime.' 'Sich einen Reim auf etwas machen' (to make a rhyme out of something) means to make sense of something. German children learn Reime (nursery rhymes) early."},
{type:"teach",trg:"die Lyrik",src:"lyric poetry",pos:"noun",gender:"f",note:"From Greek 'lyrikos' (of the lyre). One of the three Gattungen.\nPersonal, emotional, rhythmic.",example:"A: Was ist Lyrik?\nB: Gedichte. Persönliche, emotionale Texte.\nA: Und der Unterschied zu Prosa?\nB: Lyrik hat Rhythmus, Reime, Verse.",exampleSrc:"A: What is lyric poetry?\nB: Poems. Personal, emotional texts.\nA: And the difference from prose?\nB: Lyric poetry has rhythm, rhymes, verses.",funFact:"One of the three Gattungen (genres) of literature. Lyrik is personal, emotional, rhythmic. German Lyrik from Goethe to Celan is world-renowned. From Greek 'lyrikos' (of the lyre)."},
{type:"mc",q:"In einem Gedicht bilden mehrere Verse einen...",opts:["Strophe","Reim","Roman","Vers"],ans:"Strophe",hint:"A group of verse lines forming one unit in a poem. Like a paragraph in prose."},
{type:"teach",trg:"die Prosa",src:"prose",pos:"noun",gender:"f",note:"From Latin 'prosa' (straightforward). Non-verse writing.\n'Prosaisch' means both 'in prose' and 'unimaginative.'",example:"A: Ist das Prosa oder Lyrik?\nB: Prosa. Kein Rhythmus, keine Reime.\nA: Prosa klingt einfacher.\nB: Einfacher, aber nicht weniger kunstvoll.",exampleSrc:"A: Is that prose or poetry?\nB: Prose. No rhythm, no rhymes.\nA: Prose sounds simpler.\nB: Simpler, but not less artful.",funFact:"The opposite of poetry. 'Prosaisch' as an adjective has a double life: it means 'in prose' and also 'unimaginative.' Context decides which. Latin 'prosa' meant 'straightforward.'"},
{type:"teach",trg:"der Roman",src:"novel",pos:"noun",gender:"m",note:"From French 'roman.' Masculine. Der Bildungsroman\n(coming-of-age novel) is a German literary invention.",example:"A: Welchen Roman liest du gerade?\nB: Einen Roman von Thomas Mann.\nA: Der Roman ist lang, oder?\nB: Ja, aber jeder Satz lohnt sich.",exampleSrc:"A: What novel are you reading right now?\nB: A novel by Thomas Mann.\nA: The novel is long, right?\nB: Yes, but every sentence is worth it.",funFact:"From French 'roman' (novel). 'Der Bildungsroman' (coming-of-age novel) is a German literary invention. Thomas Mann's novels are landmarks of German Roman tradition."},
{type:"teach",trg:"die Kurzgeschichte",src:"short story",pos:"noun",gender:"f",note:"Kurz (short) + Geschichte (story). Die Kurzgeschichte.\nPost-war German literature excelled at Kurzgeschichten.",example:"A: Was ist eine Kurzgeschichte?\nB: Eine kurze Erzählung mit offenem Ende.\nA: Wer hat gute Kurzgeschichten geschrieben?\nB: Heinrich Boell und Wolfgang Borchert.",exampleSrc:"A: What is a short story?\nB: A short narrative with an open ending.\nA: Who wrote good short stories?\nB: Heinrich Boell and Wolfgang Borchert.",funFact:"'Kurz' (short) + 'Geschichte' (story). Post-war German literature excelled at Kurzgeschichten. Heinrich Boell and Wolfgang Borchert wrote defining examples of the form."},
{type:"teach",trg:"die Novelle",src:"novella",pos:"noun",gender:"f",note:"From Italian 'novella.' In German literary theory, a Novelle\nhas strict features: central conflict, turning point, symbolic 'Falke.'",example:"A: Ist eine Novelle eine kurze Geschichte?\nB: Ja, aber mit strengen Regeln.\nA: Welche Regeln?\nB: Ein Wendepunkt und ein symbolisches Objekt, der 'Falke.'",exampleSrc:"A: Is a novella a short story?\nB: Yes, but with strict rules.\nA: What rules?\nB: A turning point and a symbolic object, the 'falcon.'",funFact:"From Italian 'novella' (short new story). In German literary theory, a Novelle has specific features: a central conflict, a turning point, and a 'Falke' (falcon, a symbolic object). Stricter than a Kurzgeschichte."},
{type:"teach",trg:"das Drama",src:"play, drama",pos:"noun",gender:"n",note:"From Greek 'drama' (action/deed). One of the three Gattungen.\n'Kein Drama!' = No big deal! (slang).",example:"A: Was ist ein Drama?\nB: Ein Theaterstück. Dialog auf der Buehne.\nA: Und im Alltag?\nB: Da sagt man 'Kein Drama!' und meint: kein Problem.",exampleSrc:"A: What is a drama?\nB: A play. Dialogue on stage.\nA: And in everyday life?\nB: There you say 'No drama!' and mean: no problem.",funFact:"One of the three Gattungen. Schiller and Brecht are Germany's great Dramatiker. 'Kein Drama!' (No drama!) is also everyday slang for 'no big deal.'"},
{type:"fb",s:"Ein Gedicht besteht aus Versen, und mehrere Verse bilden eine {1}.",a:["Strophe"],opts:["Prosa","Strophe","Fabel","Handlung"],hint:"Several lines grouped together to form one unit in a poem. It gives structure to verse.",sSrc:"A poem consists of verses, and several verses form a stanza."},
{type:"teach",trg:"die Fabel",src:"fable",pos:"noun",gender:"f",note:"From Latin 'fabula' (story). Animal stories with moral lessons.\nAlso means 'plot': die Fabel des Romans.",example:"A: Kennst du eine Fabel?\nB: Ja, den Fuchs und die Trauben.\nA: Was ist die Moral der Fabel?\nB: Man verachtet, was man nicht erreichen kann.",exampleSrc:"A: Do you know a fable?\nB: Yes, the fox and the grapes.\nA: What is the moral of the fable?\nB: One despises what one cannot reach.",funFact:"Animal stories with moral lessons. German fables by Lessing are classics. The word also doubles as 'plot': 'Die Fabel des Romans' (the plot of the novel). Latin 'fabula' simply meant 'story.'"},
{type:"teach",trg:"die Gattung",src:"genre, category",pos:"noun",gender:"f",note:"Three literary Gattungen: Epik (prose), Lyrik (poetry),\nDramatik (drama). Every text belongs to one of these.",example:"A: Zu welcher Gattung gehört dieser Text?\nB: Zur Lyrik. Es ist ein Gedicht.\nA: Und ein Roman?\nB: Der gehört zur Epik. Erzaehlende Prosa.",exampleSrc:"A: Which genre does this text belong to?\nB: Lyric poetry. It is a poem.\nA: And a novel?\nB: That belongs to epic. Narrative prose.",funFact:"The three literary Gattungen: Epik (prose fiction), Lyrik (poetry), Dramatik (drama). Every text belongs to one. This system comes from ancient Greek poetics and German schools still teach it."},
{type:"teach",trg:"das Werk",src:"work (of art/literature)",pos:"noun",gender:"n",note:"From Germanic 'werk.' Das Werk von Kafka = the works of Kafka.\nAlso: factory (Automobilwerk).",example:"A: Kennst du Kafkas Werk?\nB: Ja, besonders 'Die Verwandlung.'\nA: Sein Werk ist zeitlos.\nB: Ja, jedes Werk überrascht neu.",exampleSrc:"A: Do you know Kafka's work?\nB: Yes, especially 'The Metamorphosis.'\nA: His work is timeless.\nB: Yes, every work surprises anew.",funFact:"From Germanic 'werk' (work/creation). 'Das Werk von Kafka' (the works of Kafka). Also: factory ('Automobilwerk'). A completed creation, the result of labor."},
{type:"teach",trg:"die Handlung",src:"plot, action",pos:"noun",gender:"f",note:"From handeln (to act). 'Die Handlung spielt in Berlin.'\nAlso: a physical shop (Buchhandlung = bookshop).",example:"A: Wo spielt die Handlung?\nB: In Berlin, im 19. Jahrhundert.\nA: Ist die Handlung spannend?\nB: Ja, voller Wendungen und Überraschungen.",exampleSrc:"A: Where does the plot take place?\nB: In Berlin, in the 19th century.\nA: Is the plot exciting?\nB: Yes, full of twists and surprises.",funFact:"From 'handeln' (to act). 'Die Handlung spielt in Berlin' (The plot takes place in Berlin). Also: a physical shop ('Buchhandlung' = bookshop). The thread of events in a story."},
{type:"teach",trg:"die Hauptfigur",src:"main character, protagonist",pos:"noun",gender:"f",note:"Haupt (main) + Figur (figure/character). Die Hauptfigur.\n'Wer ist die Hauptfigur?' is the first question in Literaturunterricht.",example:"A: Wer ist die Hauptfigur des Romans?\nB: Ein junger Mann namens Werther.\nA: Ist die Hauptfigur sympathisch?\nB: Ja, aber auch tragisch.",exampleSrc:"A: Who is the main character of the novel?\nB: A young man named Werther.\nA: Is the main character likeable?\nB: Yes, but also tragic.",funFact:"'Haupt' (main) + 'Figur' (figure/character). 'Wer ist die Hauptfigur?' (Who is the main character?) is the first question in German Literaturunterricht."},
{type:"mc",q:"Welche drei literarischen Gattungen gibt es in der deutschen Literaturtheorie?",opts:["Kurzgeschichte, Novelle, Märchen","Epik, Lyrik, Dramatik","Prosa, Vers, Strophe","Roman, Gedicht, Fabel"],ans:"Epik, Lyrik, Dramatik",hint:"The three categories that every text belongs to. Narrative prose, poetry, and theatre."}
]},
{id:"deu_r28l2b",title:"Dichtung und Wahrheit (Teil 2)",icon:"\ud83d\udcda",xp:15,board:true,steps:[
{type:"intro",title:"Dichtung und Wahrheit (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Schauplatz",src:"setting, scene",pos:"noun",gender:"m",note:"Schau (show/view) + Platz (place). Der Schauplatz.\nWhere the story unfolds. Literally a 'show-place.'",example:"A: Was ist der Schauplatz der Geschichte?\nB: Eine kleine Stadt in Sachsen.\nA: Warum ist der Schauplatz wichtig?\nB: Er bestimmt die Atmosphäre.",exampleSrc:"A: What is the setting of the story?\nB: A small town in Saxony.\nA: Why is the setting important?\nB: It determines the atmosphere.",funFact:"'Schau' (show/view) + 'Platz' (place). 'Der Schauplatz der Handlung' (the setting of the plot). Where the story unfolds. Literally a 'show-place.'"},
{type:"teach",trg:"die Epoche",src:"era, literary period",pos:"noun",gender:"f",note:"From Greek 'epoche' (stopping point). German literary history\nis organized by Epochen: Klassik, Romantik, Expressionismus.",example:"A: Aus welcher Epoche stammt dieses Gedicht?\nB: Aus der Romantik. Fruebes 19. Jahrhundert.\nA: Was kennzeichnet diese Epoche?\nB: Gefühl, Natur und Sehnsucht.",exampleSrc:"A: From which era does this poem come?\nB: From the Romantic period. Early 19th century.\nA: What characterizes this era?\nB: Emotion, nature, and longing.",funFact:"From Greek 'epoche' (stopping point). German literary history is organized by Epochen: Klassik, Romantik, Expressionismus. Each Epoche has defining characteristics."},
{type:"teach",trg:"episch",src:"epic",pos:"adj",gender:null,note:"In literary theory: belonging to Epik (narrative prose).\nIn slang: 'Das war episch!' (That was epic!).",example:"A: Ist 'Der Herr der Ringe' episch?\nB: Ja, in beiden Bedeutungen!\nA: Literarisch und umgangssprachlich?\nB: Genau. Episch als Fachbegriff und als Slang.",exampleSrc:"A: Is 'The Lord of the Rings' epic?\nB: Yes, in both meanings!\nA: Literary and colloquial?\nB: Exactly. Epic as a technical term and as slang.",funFact:"Both formal literary term and modern youth slang. In literary theory: belonging to Epik (narrative prose). In slang: 'Das war episch!' (That was epic!). From Greek 'epikos.'"},
{type:"teach",trg:"lyrisch",src:"lyrical",pos:"adj",gender:null,note:"From Greek 'lyrikos.' Belonging to Lyrik.\n'Lyrische Sprache' is emotionally charged and rhythmic.",example:"A: Dieser Text hat eine lyrische Qualitaet.\nB: Ja, fast wie ein Gedicht.\nA: Lyrisch bedeutet poetisch?\nB: Aehnlich, aber lyrisch bezieht sich auf Gefühl und Rhythmus.",exampleSrc:"A: This text has a lyrical quality.\nB: Yes, almost like a poem.\nA: Lyrical means poetic?\nB: Similar, but lyrical refers to emotion and rhythm.",funFact:"From Greek 'lyrikos.' 'Lyrische Sprache' (lyrical language) is emotionally charged and rhythmic. Also used loosely: 'ein lyrischer Moment' (a lyrical moment)."},
{type:"teach",trg:"dichterisch",src:"poetic, of a poet",pos:"adj",gender:null,note:"From Dichter + -isch. 'Dichterische Freiheit' = poetic license.\nThe adjective form of being a Dichter.",example:"A: Er hat dichterische Freiheit genutzt.\nB: Was bedeutet das?\nA: Er hat die Regeln für die Kunst gebogen.\nB: Also kuenstlerische Lizenz?",exampleSrc:"A: He used poetic license.\nB: What does that mean?\nA: He bent the rules for art.\nB: So artistic license?",funFact:"From 'Dichter' + '-isch.' 'Dichterische Freiheit' (poetic license) means a writer can bend rules for art. 'Dichterisch begabt' (poetically gifted). The adjective form of being a Dichter."},
{type:"fb",s:"Die {1} beschreibt, zu welchem Zeitabschnitt ein literarisches Werk gehoert, zum Beispiel Romantik oder Expressionismus.",a:["Epoche"],opts:["Gattung","Strophe","Lyrik","Epoche"],hint:"German literary history organizes works by these named time periods. Romantik, Expressionismus, and Barock are examples.",sSrc:"The era describes which period a literary work belongs to, for example Romanticism or Expressionism."},
{type:"tip",title:"Die drei literarischen Gattungen",text:"German literary theory divides all literature into three genres:\n\n1. Epik: narrative prose. Romane, Novellen, Kurzgeschichten, Märchen, Fabeln. A narrator tells a story.\n\n2. Lyrik: poetry. Gedichte, Verse, Strophen, Reime. Emotional, rhythmic, personal.\n\n3. Dramatik: theatre. Dramen, Tragödien, Komödien. Dialogue and stage directions, no narrator.\n\nEvery text belongs to one of these three genres. This system comes from ancient Greek poetics.",deepDive:{title:"The three Gattungen in detail",text:"This classification system dates back to Aristotle's Poetics and was formalized in German literary theory by the Romantics.\n\nEpik (Epic/Narrative): A narrator tells a story. Past tense is typical. Subtypes: Roman (novel), Novelle (novella), Kurzgeschichte (short story), Märchen (fairy tale), Fabel (fable).\n\nLyrik (Lyric): Personal expression through rhythm and imagery. Present tense is common. Subtypes: Sonett, Ballade, Ode, Elegie, Haiku.\n\nDramatik (Dramatic): Action through dialogue. No narrator. Stage directions replace description. Subtypes: Tragödie, Komödie, Tragikomödie.\n\nGerman schools test this classification regularly. Knowing the Gattung is the first step of any Textanalyse (text analysis)."}},
{type:"mc",q:"Eine Novelle unterscheidet sich von einer Kurzgeschichte, weil sie...",opts:["bestimmte Strukturmerkmale hat wie einen Wendepunkt und ein symbolisches Objekt","immer deutlich länger ist und mehr Figuren hat","immer von Tieren handelt, sich reimt und eine Moral hat","sich reimen muss und eine vollständige und klare epische Hauptstruktur auch braucht"],ans:"bestimmte Strukturmerkmale hat wie einen Wendepunkt und ein symbolisches Objekt",hint:"German literary theory gives the Novelle strict rules: one central conflict, a turning point, and a 'Falke' (falcon symbol)."},
{type:"match",pairs:[{trg:"Gedicht",src:"poem"},{trg:"Roman",src:"novel"},{trg:"Strophe",src:"stanza"},{trg:"Reim",src:"rhyme"}]},
{type:"fb",s:"Die {1} des Romans spielt in Berlin im 19. Jahrhundert.",a:["Handlung"],opts:["Gattung","Handlung","Strophe","Epoche"],hint:"The word for 'plot' or 'action' of a story. From 'handeln' (to act).",sSrc:"The plot of the novel takes place in Berlin in the 19th century."},
{type:"mc",q:"Das deutsche Wort 'Schauplatz' bedeutet...",opts:["Das Programm einer Theatershow","Ort oder Szene einer Geschichte","Ein Scheinwerfer auf der B\u00fchne","Ein Eintritt oder eine Theaterkarte"],ans:"Ort oder Szene einer Geschichte",hint:"A 'Schau-Platz' (show-place). Where the events of the plot unfold."},
{type:"mc",q:"Was bedeutet 'der Schauplatz'?",opts:["epic","prose","setting, scene","era, literary period"],ans:"setting, scene",hint:"Compound: Schau (show/view) + Platz (place). The place where the story is shown."},
{type:"fb",s:"Dieser Text hat eine {1}e Qualitaet.",a:["lyrisch"],opts:["das Gedicht","die Novelle","das Werk","lyrisch"],hint:"Cognate of English 'lyrical'. An adjective describing song-like, emotional quality.",sSrc:"This text has a lyrical quality."},
{type:"mc",q:"Was bedeutet 'dichterisch'?",opts:["verse, line of poetry","novel","setting, scene","poetic, of a poet"],ans:"poetic, of a poet",hint:"Adjective form of Dichter. The -isch suffix means 'relating to' a Dichter."}
]},
{id:"deu_r28l3",title:"Er sagte, die Backstube sei sein Königreich",icon:"\ud83d\udc51",xp:15,board:true,steps:[
{type:"intro",title:"Er sagte, die Backstube sei sein Königreich",desc:"Learn Konjunktiv I for indirect speech. Master the vocabulary of literary analysis. Report what others say in formal German.",goals:["Learn 20 words for literary analysis and reporting","Understand Konjunktiv I as 'reporter mode'","Report what others say in formal German","Analyze literary style devices"]},
{type:"teach",trg:"das Zitat",src:"quote, citation",pos:"noun",gender:"n",note:"From Latin 'citatum.' Ein bekanntes Zitat = a famous quote.\n'Zitat Ende' is said aloud in speeches.",example:"A: Kennst du ein bekanntes Zitat?\nB: Ja: 'Ich weiß, dass ich nichts weiß.'\nA: Von wem ist das Zitat?\nB: Von Sokrates. Ein zeitloses Zitat.",exampleSrc:"A: Do you know a famous quote?\nB: Yes: 'I know that I know nothing.'\nA: Who is the quote from?\nB: From Socrates. A timeless quote.",funFact:"'Zitat Ende' (end quote) is said aloud in German speeches to mark where a quotation stops. Essays always require Zitate with proper attribution. Latin 'citatum' meant 'something cited.'"},
{type:"teach",trg:"der Kontext",src:"context",pos:"noun",gender:"m",note:"From Latin 'contextus' (weaving together). Der Kontext.\n'Aus dem Kontext gerissen' = taken out of context.",example:"A: Was bedeutet das Wort im Kontext?\nB: Im Kontext betrachtet ändert sich die Bedeutung.\nA: Ohne Kontext versteht man nichts.\nB: Genau. Kontext ist alles.",exampleSrc:"A: What does the word mean in context?\nB: Viewed in context, the meaning changes.\nA: Without context, you understand nothing.\nB: Exactly. Context is everything.",funFact:"'Aus dem Kontext gerissen' (taken out of context) is every politician's favorite complaint. 'Im Kontext betrachtet' (viewed in context) changes everything. Latin 'contextus' literally meant 'woven together.'"},
{type:"teach",trg:"die Perspektive",src:"perspective, point of view",pos:"noun",gender:"f",note:"From Latin 'perspectivus.' Die Perspektive.\nLiterary analysis always asks: whose Perspektive is this?",example:"A: Aus wessen Perspektive ist die Geschichte?\nB: Aus der Perspektive des Erzählers.\nA: Und Heinrichs Perspektive?\nB: Die ist natürlich subjektiv.",exampleSrc:"A: From whose perspective is the story?\nB: From the narrator's perspective.\nA: And Heinrich's perspective?\nB: That is naturally subjective.",funFact:"Literary analysis always asks: whose Perspektive is this? 'Aus Heinrichs Perspektive' (from Heinrich's perspective) changes the entire story. Latin 'perspectivus' meant 'of looking through,' as in seeing through someone else's eyes."},
{type:"teach",trg:"das Motiv",src:"motif, theme",pos:"noun",gender:"n",note:"From Latin 'motivum' (moving). A recurring element in a text.\nAlso means 'motive' for an action.",example:"A: Was ist das zentrale Motiv?\nB: Brot. Es taucht immer wieder auf.\nA: Ein Motiv ist also ein wiederkehrendes Element?\nB: Ja, es zieht sich durch die Geschichte.",exampleSrc:"A: What is the central motif?\nB: Bread. It keeps appearing.\nA: So a motif is a recurring element?\nB: Yes, it runs through the story.",funFact:"A recurring element in a text. 'Das Brot-Motiv' (the bread motif) runs through Heinrich's stories like a thread. Also means 'motive' for an action. Latin 'motivum' meant 'moving,' because a motif moves the story forward."},
{type:"teach",trg:"das Symbol",src:"symbol",pos:"noun",gender:"n",note:"From Greek 'symbolon' (token/sign). Das Symbol.\nSomething concrete that represents something abstract.",example:"A: Was symbolisiert Brot in Heinrichs Geschichten?\nB: Gemeinschaft und Arbeit.\nA: Ein Symbol steht für etwas anderes?\nB: Ja, etwas Konkretes für etwas Abstraktes.",exampleSrc:"A: What does bread symbolize in Heinrich's stories?\nB: Community and work.\nA: A symbol stands for something else?\nB: Yes, something concrete for something abstract.",funFact:"From Greek 'symbolon' (token/sign). 'Brot ist ein Symbol für Gemeinschaft' (Bread is a symbol of community). Something concrete that represents something abstract."},
{type:"mc",q:"Was ist der Unterschied zwischen einem Vergleich und einer Metapher?",opts:["Ein Vergleich benutzt 'wie,' eine Metapher nicht","Eine Metapher benutzt 'wie,' ein Vergleich nicht","Beide sind identisch","Keines von beiden benutzt bildliche Sprache"],ans:"Ein Vergleich benutzt 'wie,' eine Metapher nicht",hint:"One device states similarity using a connecting word. The other states identity directly, without a connector."},
{type:"fb",s:"Brot ist ein {1} f\u00fcr Gemeinschaft und Arbeit in Heinrichs Geschichten.",a:["Symbol"],opts:["Vergleich","Symbol","Kontext","Zitat"],hint:"Something concrete that stands for an abstract idea. A dove represents peace; bread represents community.",sSrc:"Bread is a symbol of community and work in Heinrich's stories."},
{type:"teach",trg:"der Vergleich",src:"comparison, simile",pos:"noun",gender:"m",note:"From vergleichen (to compare). A simile uses 'wie' (like).\nDifferent from Metapher: Vergleich states likeness, not identity.",example:"A: Was ist ein Vergleich?\nB: 'Das Leben ist wie ein Buch.' Mit 'wie.'\nA: Und eine Metapher?\nB: 'Das Leben ist ein Buch.' Ohne 'wie.'",exampleSrc:"A: What is a comparison?\nB: 'Life is like a book.' With 'like.'\nA: And a metaphor?\nB: 'Life is a book.' Without 'like.'",funFact:"A simile uses 'wie' (like) or 'als' (as). Different from a Metapher, which states identity directly. 'Ein Vergleich: Das Leben ist wie ein Buch.'"},
{type:"teach",trg:"das Wortspiel",src:"pun, play on words",pos:"noun",gender:"n",note:"Wort (word) + Spiel (game/play). Das Wortspiel.\nGermans love Wortspiele despite their reputation for no humor.",example:"A: War das ein Wortspiel?\nB: Ja! Hast du es bemerkt?\nA: Ein gelungenes Wortspiel.\nB: Danke. Wortspiele sind eine Kunst.",exampleSrc:"A: Was that a pun?\nB: Yes! Did you notice it?\nA: A successful pun.\nB: Thanks. Puns are an art.",funFact:"'Wort' (word) + 'Spiel' (game/play). Germans love Wortspiele, though they are famously accused of having no humor. 'Ein gelungenes Wortspiel' (a successful pun) earns groans and respect."},
{type:"teach",trg:"die Doppeldeutigkeit",src:"ambiguity, double meaning",pos:"noun",gender:"f",note:"Doppel (double) + Deutigkeit (meaning-ness).\nMany Sprichwörter work through Doppeldeutigkeit.",example:"A: Dieses Wort hat eine Doppeldeutigkeit.\nB: Es kann zwei Dinge bedeuten?\nA: Ja, das macht es interessant.\nB: Doppeldeutigkeiten sind typisch für Sprichwörter.",exampleSrc:"A: This word has a double meaning.\nB: It can mean two things?\nA: Yes, that makes it interesting.\nB: Ambiguities are typical for proverbs.",funFact:"'Doppel' (double) + 'Deutigkeit' (meaning-ness). Having two possible interpretations. Many Sprichwörter work through Doppeldeutigkeit."},
{type:"teach",trg:"die Anspielung",src:"allusion, reference",pos:"noun",gender:"f",note:"From anspielen auf (to allude to). An indirect reference.\nSubtlety as art. Rewards those who recognize it.",example:"A: War das eine Anspielung auf Goethe?\nB: Ja, eine subtile Anspielung.\nA: Anspielungen versteht nicht jeder.\nB: Das ist der Reiz. Man muss es erkennen.",exampleSrc:"A: Was that an allusion to Goethe?\nB: Yes, a subtle allusion.\nA: Not everyone understands allusions.\nB: That is the charm. You have to recognize it.",funFact:"From 'anspielen auf' (to allude to). 'Eine Anspielung auf Goethe' (an allusion to Goethe). Indirect reference that rewards those who recognize it. Subtlety as art."},
{type:"teach",trg:"die Lektüre",src:"reading material, text being read",pos:"noun",gender:"f",note:"From Latin 'lectura' (reading). Die Lektüre.\n'Pflichtlektüre' = required reading.",example:"A: Was ist deine aktuelle Lektüre?\nB: Kafka. Schwierige, aber faszinierende Lektüre.\nA: Ist das Pflichtlektüre?\nB: Nein, freiwillig. Die beste Lektüre ist freiwillig.",exampleSrc:"A: What is your current reading?\nB: Kafka. Difficult but fascinating reading.\nA: Is that required reading?\nB: No, voluntary. The best reading is voluntary.",funFact:"'Pflichtlektüre' (required reading) is what German students must read. Interestingly, the word means both the text itself and the act of reading it. Latin 'lectura' simply meant 'reading.'"},
{type:"mc",q:"'War das eine Anspielung auf Goethe?' Was bedeutet 'Anspielung'?",opts:["ein lauter Vergleich","eine indirekte Referenz, die man erkennen muss","eine grammatische Regel","ein Zitat mit genauem Wortlaut"],ans:"eine indirekte Referenz, die man erkennen muss",hint:"From 'anspielen auf' (to allude to). Subtle, indirect. It rewards those who recognize it."},
{type:"mc",q:"Das zentrale {blank} dieses Gedichts ist die Vergänglichkeit der Zeit.",opts:["die Lektüre","die Doppeldeutigkeit","das Motiv","die Anspielung"],ans:"das Motiv",hint:"A recurring theme or subject in a literary work. Think of what drives the narrative forward."}
]},
{id:"deu_r28l3b",title:"Er sagte, die Backstube sei sein Königreich (Teil 2)",icon:"\ud83d\udc51",xp:15,board:true,steps:[
{type:"intro",title:"Er sagte, die Backstube sei sein Königreich (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"angeblich",src:"allegedly, supposedly",pos:"adv",gender:null,note:"An + geblich (from geben). Signals doubt about what is reported.\nA distancing adverb for unverified claims.",example:"A: Angeblich hat er um vier Uhr angefangen.\nB: Angeblich? Du glaubst es nicht?\nA: Hildi sagt, es war halb vier.\nB: Also ist 'vier Uhr' nur angeblich richtig.",exampleSrc:"A: Allegedly he started at four o'clock.\nB: Allegedly? You do not believe it?\nA: Hildi says it was half past three.\nB: So 'four o'clock' is only allegedly correct.",funFact:"Signals doubt about what is being reported. 'Angeblich hat er um vier Uhr angefangen' casts doubt on the claim. A distancing adverb."},
{type:"teach",trg:"anscheinend",src:"apparently",pos:"adv",gender:null,note:"An + scheinend (appearing). Based on appearances.\nSlightly less certain than offenbar, more than angeblich.",example:"A: Anscheinend war es halb vier.\nB: Das scheint wahrscheinlich.\nA: Anscheinend ist nicht sicher?\nB: Nein, es basiert auf dem, was man sieht.",exampleSrc:"A: Apparently it was half past three.\nB: That seems likely.\nA: Apparently is not certain?\nB: No, it is based on what one sees.",funFact:"'An' + 'scheinend' (appearing). Based on appearances. Slightly less certain than 'offenbar' but more confident than 'angeblich.' The scale: angeblich < anscheinend < offenbar."},
{type:"teach",trg:"bekanntlich",src:"as is well known",pos:"adv",gender:null,note:"Bekannt (known) + -lich. Signals shared knowledge.\nAcademic and journalistic register.",example:"A: Bekanntlich sind Sprichwörter zeitlos.\nB: Ja, das weiß jeder.\nA: Bekanntlich klingt sehr formell.\nB: Es passt in Aufsaetze und Reden.",exampleSrc:"A: As is well known, proverbs are timeless.\nB: Yes, everyone knows that.\nA: 'Bekanntlich' sounds very formal.\nB: It fits in essays and speeches.",funFact:"'Bekannt' (known) + '-lich.' Signals shared knowledge. The speaker assumes everyone knows this. Academic and journalistic register."},
{type:"teach",trg:"offenbar",src:"obviously, evidently",pos:"adv",gender:null,note:"Offen (open) + -bar (visible). Something openly visible.\nStronger than anscheinend, weaker than sicher.",example:"A: Offenbar hatte Heinrich recht.\nB: Ja, das ist ziemlich klar.\nA: Offenbar ist stärker als anscheinend?\nB: Ja, offenbar bedeutet: es ist fast sicher.",exampleSrc:"A: Obviously Heinrich was right.\nB: Yes, that is fairly clear.\nA: Offenbar is stronger than anscheinend?\nB: Yes, offenbar means: it is almost certain.",funFact:"'Offen' (open) + 'bar' (visible/bearable). Something openly visible. Stronger than 'anscheinend,' weaker than 'sicher.'"},
{type:"teach",trg:"laut",src:"according to (preposition)",pos:"prep",gender:null,note:"Originally 'loud,' but as preposition: 'according to.'\nLaut + dative/genitive. Compact attribution.",example:"A: Laut Heinrich begann der Tag um vier.\nB: Laut Hildi war es halb vier.\nA: Laut wem soll ich glauben?\nB: Laut der Wahrheit. Die liegt dazwischen.",exampleSrc:"A: According to Heinrich, the day began at four.\nB: According to Hildi, it was half past three.\nA: According to whom should I believe?\nB: According to the truth. It lies in between.",funFact:"Originally 'loud,' but as a preposition: 'according to.' 'Laut Heinrich begann der Tag um vier.' A compact way to attribute a statement. Preposition + dative or genitive."},
{type:"match",pairs:[{trg:"anscheinend",src:"apparently"},{trg:"bekanntlich",src:"as is well known"},{trg:"offenbar",src:"obviously, evidently"},{trg:"laut",src:"according to (preposition)"}]},
{type:"teach",trg:"behaupten",src:"to claim, to assert",pos:"verb",gender:null,note:"Be- + haupten (from Haupt = head). Not separable.\nImplies the statement may not be verified.",example:"A: Heinrich behauptet, er habe nie verschlafen.\nB: Das behauptet er.\nA: Behaupten klingt zweifelnd?\nB: Ja, man weiß nicht, ob es stimmt.",exampleSrc:"A: Heinrich claims he never overslept.\nB: That is what he claims.\nA: Behaupten sounds doubtful?\nB: Yes, you do not know if it is true.",funFact:"'Be-' + 'haupten' (from 'Haupt' = head). To claim, to assert. Implies the statement may not be verified. Not separable."},
{type:"teach",trg:"berichten",src:"to report",pos:"verb",gender:null,note:"Be- + richten (to direct/set right). Factual reporting.\nMore neutral than behaupten. Not separable.",example:"A: Verumius berichtet, was Heinrich erzählt.\nB: Berichten ist neutral?\nA: Ja, ohne Wertung.\nB: Anders als behaupten, das zweifelt.",exampleSrc:"A: Verumius reports what Heinrich tells.\nB: Berichten is neutral?\nA: Yes, without judgment.\nB: Different from behaupten, which implies doubt.",funFact:"'Be-' + 'richten' (to direct/set right). Factual reporting. More neutral than 'behaupten.' Not separable. 'Bericht' (report) is the noun."},
{type:"teach",trg:"betonen",src:"to emphasize",pos:"verb",gender:null,note:"Be- + Ton (tone/emphasis). Placing weight on something.\nNot separable. 'Betonung' is the noun.",example:"A: Heinrich betonte, dass Brot wichtig sei.\nB: Er legte besonderen Wert darauf.\nA: Betonen heißt hervorheben?\nB: Ja, einer Sache besonderen Nachdruck geben.",exampleSrc:"A: Heinrich emphasized that bread was important.\nB: He placed special value on that.\nA: Betonen means to highlight?\nB: Yes, to give something special emphasis.",funFact:"'Be-' + 'Ton' (tone/emphasis). Placing tone/weight on something. Not separable. 'Betonung' (emphasis, stress) is the noun."},
{type:"teach",trg:"schildern",src:"to describe, to depict vividly",pos:"verb",gender:null,note:"From Schild (sign/shield). More vivid than beschreiben.\nPainting a picture with words.",example:"A: Heinrich schildert die Backstube in allen Details.\nB: Man kann sie fast riechen.\nA: Schildern ist lebendiger als beschreiben?\nB: Ja, schildern malt ein Bild mit Worten.",exampleSrc:"A: Heinrich describes the bakery in all details.\nB: You can almost smell it.\nA: Schildern is more vivid than beschreiben?\nB: Yes, schildern paints a picture with words.",funFact:"From 'Schild' (sign/shield). More vivid than 'beschreiben.' Painting a picture with words. Originally: to paint a sign. 'Er schildert die Backstube in allen Details.'"},
{type:"teach",trg:"meinen",src:"to mean, to think, to be of the opinion",pos:"verb",gender:null,note:"From old German 'meinen' (to think/intend).\n'Was meinen Sie?' = What do you think?",example:"A: Was meinen Sie dazu?\nB: Ich meine, Heinrich hat recht.\nA: Er meinte, die alten Zeiten seien besser gewesen.\nB: Das meinen viele ältere Menschen.",exampleSrc:"A: What do you think about that?\nB: I think Heinrich is right.\nA: He was of the opinion that the old times were better.\nB: Many older people think that.",funFact:"'Was meinen Sie?' (What do you think?) is the polite way to ask for an opinion. 'Er meinte, die alten Zeiten seien besser gewesen' uses Konjunktiv I for indirect speech."},
{type:"match",pairs:[{trg:"berichten",src:"to report"},{trg:"betonen",src:"to emphasize"},{trg:"schildern",src:"to describe, to depict vividly"},{trg:"meinen",src:"to mean, to think, to be of the opinion"}]},
{type:"tip",title:"Konjunktiv I: Der Reporter-Modus",text:"German has a special verb form for reported speech: the Konjunktiv I.\n\nFormation: verb stem + endings (-e, -est, -e, -en, -et, -en).\n\nsein: er sei\nhaben: er habe\nkönnen: er könne\nsagen: er sage\n\nExample: 'Heinrich sagte, die Backstube sei sein Königreich.'\n\nThe Konjunktiv I signals: 'I am reporting, not giving my own opinion.'\n\nUsage: newspapers, academic writing, formal language.\nIn everyday speech, many speakers use Konjunktiv II (wäre, hätte) instead of Konjunktiv I, but B2 learners must be able to recognize and produce the Konjunktiv I.",deepDive:{title:"Konjunktiv I: Formation and usage",text:"The Konjunktiv I is formed from the verb stem (infinitive minus -en) plus endings: -e, -est, -e, -en, -et, -en.\n\nWhen Konjunktiv I is identical to the indicative (e.g., 'sie haben' = 'sie haben'), German switches to Konjunktiv II instead: 'sie hätten.' This happens mainly in ich and wir/sie forms.\n\nThe Konjunktiv I is used in:\n1. Newspapers and news broadcasts\n2. Academic writing\n3. Formal speech and reports\n4. Legal documents\n\nIn everyday speech, most Germans use Konjunktiv II or 'würde + Infinitiv' for indirect speech. But recognizing and producing Konjunktiv I is essential at B2 level."}},
{type:"verb_table",title:"Konjunktiv I: Bildung",groups:[{label:"Wichtige Formen",rows:[{pronoun:"sein",form:"er/sie sei",src:"he/she be (reported)"},{pronoun:"haben",form:"er/sie habe",src:"he/she have (reported)"},{pronoun:"können",form:"er/sie könne",src:"he/she can (reported)"},{pronoun:"müssen",form:"er/sie müsse",src:"he/she must (reported)"},{pronoun:"wollen",form:"er/sie wolle",src:"he/she want (reported)"},{pronoun:"sagen",form:"er/sie sage",src:"he/she say (reported)"}]},{label:"Konjugation: sein (Konj. I)",rows:[{pronoun:"ich",form:"sei",src:"I be (reported)"},{pronoun:"du",form:"sei(e)st",src:"you be"},{pronoun:"er/sie/es",form:"sei",src:"he/she/it be"},{pronoun:"wir",form:"seien",src:"we be"},{pronoun:"ihr",form:"sei(e)t",src:"you all be"},{pronoun:"sie/Sie",form:"seien",src:"they/you be"}]}]},
{type:"mc",q:"Verumius schreibt: 'Heinrich erzählte, die Backstube sei sein Königreich.' Warum 'sei' statt 'ist'?",opts:["Indirekte Rede markiert, was Heinrich sagte","Es markiert eine abgeschlossene Vergangenheit","Es dr\u00fcckt einen pers\u00f6nlichen Wunsch aus","Es formuliert eine direkte Frage"],ans:"Indirekte Rede markiert, was Heinrich sagte",hint:"This special verb form signals that you are reporting someone else's words, not your own opinion."},
{type:"fb",s:"Heinrich erzählte, er {1} jeden Morgen um vier Uhr aufgestanden.",a:["sei"],opts:["sei","ist","war","wäre"],hint:"In reporter mode the auxiliary verb changes. Past tense + Partizip II gives the reported past.",sSrc:"Heinrich told that he had gotten up at four o'clock every morning."},
{type:"mc",q:"Was bedeutet 'angeblich'?",opts:["to report","allegedly, supposedly","ambiguity, double meaning","quote, citation"],ans:"allegedly, supposedly",hint:"From angeben (to state/claim). It signals that the speaker doubts the truth."},
{type:"fb",s:"{1} war es halb vier.",a:["anscheinend"],opts:["anscheinend","angeblich","das Symbol","betonen"],hint:"From Schein (appearance). The adverb meaning 'by the look of things' or 'apparently'.",sSrc:"Apparently it was half past three."},
{type:"mc",q:"Was bedeutet 'bekanntlich'?",opts:["to mean, to think, to be of the opinion","obviously, evidently","as is well known","according to (preposition)"],ans:"as is well known",hint:"From bekannt (familiar) + -lich. The adverb used when something is universally acknowledged."},
{type:"fb",s:"{1} hatte Heinrich recht.",a:["offenbar"],opts:["die Lektüre","offenbar","meinen","der Vergleich"],hint:"From offen (open) + bar (bearing). Something that lies open for all to see.",sSrc:"Obviously Heinrich was right."},
{type:"mc",q:"Was bedeutet 'berichten'?",opts:["perspective, point of view","to mean, to think, to be of the opinion","reading material, text being read","to report"],ans:"to report",hint:"The verb derived from Bericht. What journalists do when covering a story."},
{type:"fb",s:"{1} ist lebendiger als beschreiben?",a:["schildern"],opts:["offenbar","bekanntlich","das Wortspiel","schildern"],hint:"From Schild (sign/shield). To paint a vivid picture with words, more expressive than beschreiben.",sSrc:"Schildern is more vivid than beschreiben?"},
{type:"mc",q:"Was bedeutet 'meinen'?",opts:["to mean, to think, to be of the opinion","quote, citation","allusion, reference","context"],ans:"to mean, to think, to be of the opinion",hint:"Consider what this word expresses in everyday conversation."}
]},
{id:"deu_r28l4",title:"Als ob er alles wüsste",icon:"\ud83c\udfad",xp:15,board:true,steps:[
{type:"intro",title:"Als ob er alles wüsste",desc:"Master 'als ob' + Konjunktiv II for unreal comparisons. Learn literary character and genre vocabulary. Combine indirect speech with hypothetical comparison.",goals:["Master 'als ob' + Konjunktiv II for unreal comparisons","Learn vocabulary for characters and literary styles","Understand the short form: 'als wäre' (inversion)","Combine Konjunktiv I (speech) with Konjunktiv II (comparison)"]},
{type:"teach",trg:"der Erzähler",src:"narrator",pos:"noun",gender:"m",note:"From erzählen (to narrate). Der Erzähler.\nIn Literaturanalyse: 'der allwissende Erzähler' = omniscient narrator.",example:"A: Wer ist der Erzähler dieser Geschichte?\nB: Ein allwissender Erzähler. Er weiß alles.\nA: Und Heinrich? Ist er auch ein Erzähler?\nB: Ja, ein geborener Erzähler.",exampleSrc:"A: Who is the narrator of this story?\nB: An omniscient narrator. He knows everything.\nA: And Heinrich? Is he also a narrator?\nB: Yes, a born narrator.",funFact:"In literary analysis: 'der allwissende Erzähler' (the omniscient narrator) knows everything. 'Der Ich-Erzähler' narrates in first person. Heinrich is a natural Erzähler."},
{type:"teach",trg:"die Erzählerin",src:"narrator (female)",pos:"noun",gender:"f",note:"Erzähler + -in. Die Erzählerin.\n'Die unzuverlässiige Erzählerin' = the unreliable narrator.",example:"A: Ist die Erzählerin zuverlässiig?\nB: Nein, sie ist eine unzuverlässiige Erzählerin.\nA: Man kann ihr nicht vertrauen?\nB: Genau. Sie verändert die Fakten.",exampleSrc:"A: Is the narrator reliable?\nB: No, she is an unreliable narrator.\nA: You cannot trust her?\nB: Exactly. She changes the facts.",funFact:"'Die unzuverlässiige Erzählerin' (the unreliable narrator) is a literary device. The reader cannot fully trust what she reports. The -in suffix creates the feminine form."},
{type:"teach",trg:"die Nebenfigur",src:"secondary character",pos:"noun",gender:"f",note:"Neben (beside/secondary) + Figur (figure/character).\nThe supporting cast. Essential but not the star.",example:"A: Ist Hildi eine Nebenfigur?\nB: In Heinrichs Geschichten, ja.\nA: Nebenfiguren bereichern die Handlung.\nB: Ohne sie wäre die Geschichte flach.",exampleSrc:"A: Is Hildi a secondary character?\nB: In Heinrich's stories, yes.\nA: Secondary characters enrich the plot.\nB: Without them the story would be flat.",funFact:"'Neben' (beside/secondary) + 'Figur' (figure/character). 'Nebenfiguren bereichern die Handlung' (Secondary characters enrich the plot). Not the star, but essential."},
{type:"teach",trg:"die Tragödie",src:"tragedy",pos:"noun",gender:"f",note:"From Greek 'tragodia' (goat song). Die Tragödie.\nSchiller's 'Die Räuber' and Goethe's 'Faust' are world literature.",example:"A: Ist 'Faust' eine Tragödie?\nB: Ja, eine der größten deutschen Tragödien.\nA: Was macht eine Tragödie aus?\nB: Der Held scheitert an seinem Schicksal.",exampleSrc:"A: Is 'Faust' a tragedy?\nB: Yes, one of the greatest German tragedies.\nA: What defines a tragedy?\nB: The hero fails because of his fate.",funFact:"From Greek 'tragodia' (goat song). One of the oldest dramatic forms. German Tragödien by Schiller and Goethe are world literature. 'Das ist eine Tragödie!' is also everyday drama."},
{type:"teach",trg:"die Poesie",src:"poetry, poetic quality",pos:"noun",gender:"f",note:"From Greek 'poiesis' (making/creating). Broader than Lyrik:\nPoesie is the beauty and art in language itself.",example:"A: Gibt es Poesie in Sprichwörtern?\nB: Ja, alltägliche Poesie. Einfach und schoen.\nA: Poesie ist mehr als Gedichte?\nB: Ja, Poesie ist Schoenheit in der Sprache.",exampleSrc:"A: Is there poetry in proverbs?\nB: Yes, everyday poetry. Simple and beautiful.\nA: Poetry is more than poems?\nB: Yes, poetry is beauty in language.",funFact:"From Greek 'poiesis' (making/creating). Broader than Lyrik: Poesie is the beauty and art in language itself. 'Alltägliche Poesie' (everyday poetry) is found in Sprichwörter."},
{type:"mc",q:"Welches Wort beschreibt die Schoenheit und Kunst in der Sprache selbst, breiter als nur Gedichte?",opts:["die Poesie","die Lyrik","die Prosa","der Vers"],ans:"die Poesie",hint:"From Greek 'poiesis' (making/creating). Broader than Lyrik: the beauty and art in language itself."},
{type:"teach",trg:"der Schriftsteller",src:"writer, author",pos:"noun",gender:"m",note:"Schrift (writing) + Steller (one who places). Der Schriftsteller.\nMore prestige than 'Autor.'",example:"A: Ist Thomas Mann ein Autor oder ein Schriftsteller?\nB: Ein Schriftsteller. Das klingt literarischer.\nA: Was ist der Unterschied?\nB: Schriftsteller schreiben literarische Werke.",exampleSrc:"A: Is Thomas Mann an author or a Schriftsteller?\nB: A Schriftsteller. That sounds more literary.\nA: What is the difference?\nB: Schriftsteller write literary works.",funFact:"'Schrift' (writing) + 'Steller' (one who places). More prestige than 'Autor': a Schriftsteller creates literary works. 'Freier Schriftsteller' (freelance writer) is a German tax category."},
{type:"teach",trg:"die Schriftstellerin",src:"writer, author (female)",pos:"noun",gender:"f",note:"Schriftsteller + -in. Die Schriftstellerin.\nHerta Mueller (Nobel Prize), Juli Zeh: great Schriftstellerinnen.",example:"A: Kennst du eine deutsche Schriftstellerin?\nB: Herta Mueller. Sie hat den Nobelpreis gewonnen.\nA: Eine bedeutende Schriftstellerin.\nB: Ja, ihre Werke sind kraftvoll.",exampleSrc:"A: Do you know a German female writer?\nB: Herta Mueller. She won the Nobel Prize.\nA: An important writer.\nB: Yes, her works are powerful.",funFact:"Christa Wolf, Herta Mueller (Nobel Prize), Juli Zeh: Germany's great Schriftstellerinnen shape contemporary German literature. The -in suffix creates the feminine form."},
{type:"teach",trg:"der Zeitgenosse",src:"contemporary",pos:"noun",gender:"m",note:"Zeit (time) + Genosse (companion). Der Zeitgenosse.\nSomeone who lives in the same era.",example:"A: War Schiller ein Zeitgenosse von Goethe?\nB: Ja, sie lebten in derselben Epoche.\nA: Und umgangssprachlich?\nB: 'Ein seltsamer Zeitgenosse' heißt: ein komischer Typ.",exampleSrc:"A: Was Schiller a contemporary of Goethe?\nB: Yes, they lived in the same era.\nA: And colloquially?\nB: 'A strange Zeitgenosse' means: a weird fellow.",funFact:"'Zeit' (time) + 'Genosse' (companion). 'Goethes Zeitgenossen' (Goethe's contemporaries). Also colloquially: 'ein seltsamer Zeitgenosse' (a strange fellow)."},
{type:"teach",trg:"fiktiv",src:"fictional",pos:"adj",gender:null,note:"From Latin 'fictivus' (feigned). The opposite of real/wahr.\n'Fiktive Figuren' do not exist but feel real.",example:"A: Ist Verumius fiktiv?\nB: Ja, eine fiktive Figur.\nA: Aber er fühlt sich real an.\nB: Das ist gute Fiktion.",exampleSrc:"A: Is Verumius fictional?\nB: Yes, a fictional character.\nA: But he feels real.\nB: That is good fiction.",funFact:"'Eine fiktive Geschichte' (a fictional story) is the opposite of 'real' or 'wahr.' The magic of good literature: fiktive characters do not exist but feel real. Latin 'fictivus' meant 'feigned.'"},
{type:"teach",trg:"klassisch",src:"classic, classical",pos:"adj",gender:null,note:"From Latin 'classicus.' In German: 'die Klassik' is a specific\nEpoche (Goethe and Schiller era, ~1786-1832).",example:"A: Ist das klassische Literatur?\nB: Ja, aus der Weimarer Klassik.\nA: Klassisch bedeutet auch 'typisch'?\nB: Ja. 'Das ist klassisch!' heißt: typisch!",exampleSrc:"A: Is that classical literature?\nB: Yes, from the Weimar Classical period.\nA: Klassisch also means 'typical'?\nB: Yes. 'That is classic!' means: typical!",funFact:"'Die Klassik' is a specific Epoche in German literary history (Goethe and Schiller era, ~1786-1832). Also everyday: 'Das ist klassisch!' (That is classic/typical!)."},
{type:"fb",s:"Herta Mueller ist eine bedeutende deutsche {1}. Sie hat den Nobelpreis gewonnen.",a:["Schriftstellerin"],opts:["Dichterin","Schriftstellerin","Erzählerin","Nebenfigur"],hint:"The feminine form of the word for a literary writer. Schrift (writing) + Steller (one who places) + -in.",sSrc:"Herta Mueller is an important German writer. She won the Nobel Prize."},
{type:"mc",q:"Goethe war ein bedeutender {blank} seiner Epoche. Wer in derselben Zeit lebt, ist ein...?",opts:["der Dichter","der Zeitgenosse","der Erzähler","der Schriftsteller"],ans:"der Zeitgenosse",hint:"Someone who lives in the same time period. 'Zeit' (time) + 'Genosse' (companion) combined."},
{type:"fb",s:"Die Geschichte ist nicht real, sie ist {1}.",a:["fiktiv"],opts:["fiktiv","klassisch","tragisch","satirisch"],hint:"From Latin 'fictivus.' The opposite of real or true. Describes invented stories.",sSrc:"The story is not real, it is fictional."},
{type:"mc",q:"'Faust' von Goethe gehoert zur {blank} deutschen Literatur.",opts:["satirischen","prosaischen","klassischen","fiktiven"],ans:"klassischen",hint:"Belonging to a revered literary tradition. Think of the Weimar period and its great works."}
]},
{id:"deu_r28l4b",title:"Als ob er alles wüsste (Teil 2)",icon:"\ud83c\udfad",xp:15,board:true,steps:[
{type:"intro",title:"Als ob er alles wüsste (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"tragisch",src:"tragic",pos:"adj",gender:null,note:"From Greek 'tragikos.' Related to Tragödie.\n'Tragischerweise' (tragically) is the adverb.",example:"A: Hat die Geschichte ein tragisches Ende?\nB: Ja, leider. Die Hauptfigur scheitert.\nA: Tragische Geschichten sind oft die besten.\nB: Weil sie ehrlich sind.",exampleSrc:"A: Does the story have a tragic ending?\nB: Yes, unfortunately. The main character fails.\nA: Tragic stories are often the best.\nB: Because they are honest.",funFact:"From Greek 'tragikos.' Related to Tragödie. 'Tragischerweise' (tragically) is the adverb. Heinrich's stories sometimes have tragische Elemente."},
{type:"teach",trg:"satirisch",src:"satirical",pos:"adj",gender:null,note:"From Latin 'satiricus.' Using humor to critique society.\nGerman Satire tradition: from Heinrich Heine to Jan Boehmermann.",example:"A: Ist dieser Text satirisch?\nB: Ja, er kritisiert die Gesellschaft mit Humor.\nA: Deutsche Satire ist oft scharf.\nB: Scharf, aber treffend.",exampleSrc:"A: Is this text satirical?\nB: Yes, it criticizes society with humor.\nA: German satire is often sharp.\nB: Sharp, but on point.",funFact:"German Satire has a long tradition: from Heinrich Heine to Jan Boehmermann. 'Ein satirischer Kommentar' uses humor to critique society."},
{type:"teach",trg:"ironisch",src:"ironic",pos:"adj",gender:null,note:"From Greek 'eironeia' (dissimulation). Saying the opposite\nof what you mean. German Ironie is just more subtle.",example:"A: Das war ironisch gemeint.\nB: Ich habe es nicht erkannt.\nA: Deutsche Ironie ist subtil.\nB: Ja, man muss den Tonfall hören.",exampleSrc:"A: That was meant ironically.\nB: I did not recognize it.\nA: German irony is subtle.\nB: Yes, you have to hear the tone of voice.",funFact:"From Greek 'eironeia' (dissimulation). Saying the opposite of what you mean. Germans are accused of not understanding irony, but German Ironie is just more subtle."},
{type:"teach",trg:"humorvoll",src:"humorous",pos:"adj",gender:null,note:"Humor + voll (full of). German humor exists.\nIt is just structured differently.",example:"A: Heinrichs Geschichten sind humorvoll.\nB: Ja, auf eine trockene, warme Art.\nA: Deutscher Humor ist trocken?\nB: Trocken, aber tief. Und überraschend.",exampleSrc:"A: Heinrich's stories are humorous.\nB: Yes, in a dry, warm way.\nA: German humor is dry?\nB: Dry, but deep. And surprising.",funFact:"'Humor' + 'voll' (full of). German humor exists. It is just structured differently. Heinrich's stories are humorvoll in a dry, warm way."},
{type:"teach",trg:"metaphorisch",src:"metaphorical",pos:"adj",gender:null,note:"From Metapher + -isch. 'Metaphorisch gesprochen'\nintroduces a figurative comparison.",example:"A: Brot als metaphorisches Symbol?\nB: Ja, metaphorisch steht Brot für Gemeinschaft.\nA: Metaphorisch gesprochen also.\nB: Genau. Nicht wörtlich, sondern bildlich.",exampleSrc:"A: Bread as a metaphorical symbol?\nB: Yes, metaphorically bread stands for community.\nA: Metaphorically speaking then.\nB: Exactly. Not literally, but figuratively.",funFact:"From 'Metapher' + '-isch.' 'Metaphorisch gesprochen' (metaphorically speaking) introduces a figurative comparison. 'Brot als metaphorisches Symbol' in Heinrich's tales."},
{type:"mc",q:"Wenn eine Geschichte 'ironisch' ist, dann...",opts:["sagt der Autor das Gegenteil von dem, was er meint","ist sie nur fuer Kinder geschrieben","ist sie immer lustig und unterhaltsam","handelt sie von Eisen und Metall"],ans:"sagt der Autor das Gegenteil von dem, was er meint",hint:"From Greek 'eironeia' (dissimulation). The speaker says the opposite of what is meant."},
{type:"teach",trg:"sinnbildlich",src:"symbolic, allegorical",pos:"adj",gender:null,note:"Sinn (sense/meaning) + Bild (image) + -lich.\nA German alternative to 'symbolisch.' Image carries meaning.",example:"A: Das Brot ist sinnbildlich für Arbeit.\nB: Sinnbildlich? Also symbolisch?\nA: Ja, das Bild (Brot) trägt den Sinn (Arbeit).\nB: Ein schönes Wort.",exampleSrc:"A: The bread is symbolic of work.\nB: Symbolic? So symbolically?\nA: Yes, the image (bread) carries the meaning (work).\nB: A beautiful word.",funFact:"'Sinn' (sense/meaning) + 'Bild' (image) + '-lich.' 'Sinnbildlich für das Leben' (symbolic of life). A German alternative to 'symbolisch.' The image (Bild) carries meaning (Sinn)."},
{type:"teach",trg:"als ob",src:"as if",pos:"conj",gender:null,note:"Als (as) + ob (if/whether). Introduces unreal comparison.\nAlways followed by Konjunktiv II. Verb goes to END.",example:"A: Er tut als ob er alles wüsste.\nB: Wüsste? Warum nicht 'weiß'?\nA: Weil es nicht real ist. 'Als ob' braucht Konjunktiv II.\nB: Also: er weiß es nicht wirklich?",exampleSrc:"A: He acts as if he knew everything.\nB: Knew? Why not 'knows'?\nA: Because it is not real. 'Als ob' requires Konjunktiv II.\nB: So: he does not really know?",funFact:"'Als' (as) + 'ob' (if/whether). 'Er tut als ob er alles wüsste' (He acts as if he knew everything). Always followed by Konjunktiv II. Verb goes to the END of the clause."},
{type:"teach",trg:"als wenn",src:"as if (colloquial)",pos:"conj",gender:null,note:"Als + wenn. Same meaning as als ob. Slightly more colloquial.\nSame grammar: Konjunktiv II, verb at end.",example:"A: Er spricht, als wenn er ein Dichter wäre.\nB: Ist das dasselbe wie 'als ob'?\nA: Ja, nur etwas umgangssprachlicher.\nB: Also als ob = als wenn?",exampleSrc:"A: He speaks as if he were a poet.\nB: Is that the same as 'als ob'?\nA: Yes, just slightly more colloquial.\nB: So als ob = als wenn?",funFact:"'Als' + 'wenn.' Same meaning as 'als ob': as if. Slightly more colloquial. Same grammar: Konjunktiv II, verb at end."},
{type:"teach",trg:"wie wenn",src:"as if (informal)",pos:"conj",gender:null,note:"Wie (how/like) + wenn (if/when). The most informal variant.\n'Es fühlt sich an, wie wenn man nach Hause kommt.'",example:"A: Es fühlt sich an, wie wenn man nach Hause kommt.\nB: Wie wenn? Das klingt informell.\nA: Ja, im Alltag sagt man das.\nB: Also die lockere Version von 'als ob'?",exampleSrc:"A: It feels like when you come home.\nB: Wie wenn? That sounds informal.\nA: Yes, people say that in everyday speech.\nB: So the casual version of 'als ob'?",funFact:"'Wie' (how/like) + 'wenn' (if/when). The most informal of the three. Same structure as als ob/als wenn but with 'wie' instead of 'als.'"},
{type:"teach",trg:"als wäre",src:"as if (were) (literary short form)",pos:"conj",gender:null,note:"Als + wäre (Konjunktiv II of sein). The SHORT form:\nals alone, verb directly after (inversion). No ob/wenn needed.",example:"A: Er spricht, als wäre er ein Experte.\nB: Kein 'ob' nach 'als'?\nA: Nein, das ist die kurze Form. Eleganter.\nB: Also: als + Verb sofort danach?",exampleSrc:"A: He speaks as if he were an expert.\nB: No 'ob' after 'als'?\nA: No, that is the short form. More elegant.\nB: So: als + verb immediately after?",funFact:"The SHORT form: 'als' alone, with verb directly after (inversion). No 'ob' or 'wenn' needed. More elegant and literary. 'Er spricht, als wäre er ein Experte.'"},
{type:"tip",title:"Als ob + Konjunktiv II: Irreale Vergleiche",text:"German compares reality with imagination using 'als ob.' The Konjunktiv II signals that something is NOT reality, it only LOOKS that way.\n\nTwo main patterns exist:\n- Als ob with the verb at the END of the clause: 'Er tut, als ob er alles w\u00fcsste.'\n- Als alone with INVERSION (no ob needed): 'Er tut, als w\u00fcsste er alles.' This short form is more elegant and literary.\n\nBoth mean the same thing. Two informal variants also exist: 'als wenn' (slightly colloquial) and 'wie wenn' (most informal). All four patterns take Konjunktiv II.\n\nCommon verb forms after als ob: w\u00e4re, h\u00e4tte, w\u00fcsste, k\u00f6nnte.\n\nIn Heinrich's stories: 'Er erz\u00e4hlte es, als w\u00e4re er noch jung.' He is no longer young, but it LOOKS that way.",deepDive:{title:"Als ob: Full grammar",text:"The four patterns:\n1. als ob + Konj. II + verb END: Er tut, als ob er reich wäre.\n2. als + Konj. II + INVERSION: Er tut, als wäre er reich.\n3. als wenn + Konj. II + verb END: Er tut, als wenn er reich wäre.\n4. wie wenn + Konj. II + verb END: Er tut, wie wenn er reich wäre.\n\nAll four mean the same thing. Patterns 1-2 are standard. Pattern 2 is most elegant. Pattern 3 is common in speech. Pattern 4 is informal.\n\nImportant: The 'würde + Infinitiv' form also works after als ob: 'Er tut, als ob er alles wissen würde.' Grammatically correct but less elegant than Konjunktiv II directly.\n\nRecognition tip: whenever you see 'als ob,' 'als wenn,' 'wie wenn,' or 'als' followed immediately by a Konjunktiv II verb, you are looking at an unreal comparison."}},
{type:"verb_table",title:"Als ob + Konjunktiv II: Muster",groups:[{label:"Volle Form (als ob)",rows:[{pronoun:"als ob + sein",form:"als ob er/sie ... wäre",src:"as if he/she were"},{pronoun:"als ob + haben",form:"als ob er/sie ... hätte",src:"as if he/she had"},{pronoun:"als ob + wissen",form:"als ob er/sie ... wüsste",src:"as if he/she knew"},{pronoun:"als ob + können",form:"als ob er/sie ... könnte",src:"as if he/she could"}]},{label:"Kurze Form (als + Inversion)",rows:[{pronoun:"als + sein",form:"als wäre er/sie ...",src:"as if he/she were"},{pronoun:"als + haben",form:"als hätte er/sie ...",src:"as if he/she had"},{pronoun:"als + wissen",form:"als wüsste er/sie ...",src:"as if he/she knew"},{pronoun:"als + können",form:"als könnte er/sie ...",src:"as if he/she could"}]}]},
{type:"teach",trg:"existieren",src:"to exist",pos:"verb",gender:null,note:"From Latin 'existere' (to stand out, to come into being).\nRegular -ieren verb. 'Noch existieren' = to still exist.",example:"A: Existiert die alte Baeckerei noch?\nB: Nein, sie existiert nicht mehr.\nA: Wann hat sie aufgehört zu existieren?\nB: Vor zwanzig Jahren. Aber in Heinrichs Geschichten existiert sie weiter.",exampleSrc:"A: Does the old bakery still exist?\nB: No, it no longer exists.\nA: When did it stop existing?\nB: Twenty years ago. But in Heinrich's stories it goes on existing.",funFact:"German Existenzphilosophie (existentialism) made this root famous worldwide. 'Die Existenz' is the noun, 'das existenzielle Problem' the adjective form. Borrowed via French from Latin 'existere' (to stand out, to come into being)."},
{type:"drag_fill",s:"Heinrich redet über die alte Baeckerei, {1} {2} sie noch {3}.",blanks:{"1":"als","2":"ob","3":"existierte"},pool:["als","ob","existierte","existiert","dass","wäre"],hint:"The 'als ob' construction: als ob + Konjunktiv II at the end. The bakery no longer exists."},
{type:"match",pairs:[{trg:"ironisch",src:"ironic"},{trg:"satirisch",src:"satirical"},{trg:"humorvoll",src:"humorous"},{trg:"tragisch",src:"tragic"}]},
{type:"mc",q:"Was bedeutet 'metaphorisch'?",opts:["humorous","metaphorical","narrator","tragedy"],ans:"metaphorical",hint:"A direct cognate from Greek via Latin. Using imagery to represent something else."},
{type:"fb",s:"Das Brot ist {1} für Arbeit.",a:["sinnbildlich"],opts:["sinnbildlich","ironisch","als wenn","tragisch"],hint:"Compound: Sinn (meaning/sense) + Bild (image) + -lich. A word meaning 'symbolic'.",sSrc:"The bread is symbolic of work."},
{type:"mc",q:"Was bedeutet 'existieren'?",opts:["tragedy","writer, author","to exist","narrator (female)"],ans:"to exist",hint:"A Latin loan word, nearly identical in English and French. To be, to have being."}
]},
{id:"deu_r28l5",title:"Laut Heinrich",icon:"\uD83D\uDCDC",xp:15,board:true,steps:[
{type:"intro",title:"Laut Heinrich",desc:"Heinrich remembers the bakery of the 1960s. Learn how to shift tenses in indirect speech, distinguish literal from figurative meaning, and report narratives correctly.",goals:["Master tense shifting in indirect speech","Distinguish literal and figurative meaning","Report narratives precisely in formal German"]},
{type:"teach",trg:"die Übung",src:"the practice, the exercise",pos:"noun",gender:"f",note:"Feminine noun. From 'üben' (to practice).\n'Übung macht den Meister' (practice makes the master).",example:"A: Wie hast du so gut Deutsch gelernt?\nB: Übung! Übung macht den Meister.\nA: Das stimmt. Wie viel Übung?\nB: Jeden Tag mindestens eine Stunde.",exampleSrc:"A: How did you learn German so well?\nB: Practice! Practice makes the master.\nA: That is true. How much practice?\nB: At least one hour every day.",funFact:"'Übung macht den Meister' is one of Germany's most beloved Sprichwörter. Every German knows it by heart. The word comes from 'üben' (to practice), and the -ung suffix creates a feminine action noun."},
{type:"teach",trg:"der Anfang",src:"the beginning",pos:"noun",gender:"m",note:"Masculine noun. From 'anfangen' (to begin).\n'Aller Anfang ist schwer' (every beginning is hard).",example:"A: Der Anfang war wirklich schwer.\nB: Ja, aller Anfang ist schwer.\nA: Aber du hast nicht aufgegeben.\nB: Nein, nach dem Anfang wird es leichter.",exampleSrc:"A: The beginning was really hard.\nB: Yes, every beginning is hard.\nA: But you did not give up.\nB: No, after the beginning it gets easier.",funFact:"'An' + 'Fang' (catching). A beginning catches the first moment. 'Am Anfang' (at the beginning), 'von Anfang an' (from the very start). The proverb 'Aller Anfang ist schwer' captures a universal truth."},
{type:"teach",trg:"bildlich",src:"figurative, metaphorical",pos:"adj",gender:null,note:"'Bild' (image) + '-lich.' The opposite of 'wörtlich.'\n'Bildlich gesprochen' (figuratively speaking).",example:"A: Meinst du das bildlich oder wörtlich?\nB: Bildlich! Die Sprache ist eine Brücke.\nA: Das ist ein schönes Bild.\nB: Sprichwörter sind fast immer bildlich.",exampleSrc:"A: Do you mean that figuratively or literally?\nB: Figuratively! Language is a bridge.\nA: That is a beautiful image.\nB: Proverbs are almost always figurative.",funFact:"From 'Bild' (image/picture). Using images to convey meaning. Sprichwörter are often bildlich: 'Morgenstund hat Gold im Mund' does not mean there is actual gold in anyone's mouth."},
{type:"teach",trg:"wörtlich",src:"literal, word-for-word",pos:"adj",gender:null,note:"'Wort' (word) + '-lich.' The opposite of 'bildlich.'\n'Wörtlich genommen' (taken literally).",example:"A: Das ist nicht wörtlich gemeint.\nB: Ich weiß. Wörtlich wäre es unsinnig.\nA: Genau. Sprichwörter sind selten wörtlich.\nB: Man muss den übertragenen Sinn verstehen.",exampleSrc:"A: That is not meant literally.\nB: I know. Literally it would be nonsensical.\nA: Exactly. Proverbs are rarely literal.\nB: You have to understand the figurative meaning.",funFact:"From 'Wort' (word). 'Wörtlich genommen' (taken literally) means understanding words at face value. 'Das ist nicht wörtlich gemeint' warns against surface interpretation."},
{type:"teach",trg:"still",src:"quiet, still",pos:"adj",gender:null,note:"Also an adverb. 'Stille Wasser sind tief' (still waters run deep).\n'Die Stille' (the silence) is the noun.",example:"A: Warum bist du so still?\nB: Stille Wasser sind tief, sagt man.\nA: Du denkst also nach?\nB: Ja. Still sein heißt nicht leer sein.",exampleSrc:"A: Why are you so quiet?\nB: Still waters run deep, they say.\nA: So you are thinking?\nB: Yes. Being quiet does not mean being empty.",funFact:"This Sprichwort warns that quiet people may have deep thoughts or hidden depths. Related to English 'still.' 'Die Stille' (silence) is the noun. Do not underestimate the silent ones."},
{type:"match",pairs:[{trg:"der Anfang",src:"the beginning"},{trg:"bildlich",src:"figurative, metaphorical"},{trg:"wörtlich",src:"literal, word-for-word"},{trg:"still",src:"quiet, still"}]},
{type:"teach",trg:"im übertragenen Sinne",src:"in the figurative sense",pos:"adv",gender:null,note:"Fixed phrase. 'Im' (in the) + 'übertragenen' (transferred) + 'Sinne' (sense).\nIntroduces metaphorical interpretation.",example:"A: Brot ist das Wichtigste, sagte Heinrich.\nB: Im übertragenen Sinne bedeutet das: Grundlagen zaehlen.\nA: Und im wörtlichen Sinne?\nB: Da bedeutet es einfach: Brot ist lecker.",exampleSrc:"A: Bread is the most important thing, said Heinrich.\nB: In the figurative sense that means: fundamentals count.\nA: And in the literal sense?\nB: There it simply means: bread is delicious.",funFact:"The idea has been 'transferred' (übertragen) from literal to symbolic. 'Im übertragenen Sinne bedeutet das...' is the standard phrase for introducing a metaphorical interpretation in German."},
{type:"teach",trg:"sprichwörtlich",src:"proverbial",pos:"adj",gender:null,note:"'Sprichwort' + '-lich.' Something so well-known it has become a saying.\n'Die sprichwörtliche Puenktlichkeit.'",example:"A: Die Deutschen sind sprichwörtlich puenktlich.\nB: Ja, die sprichwörtliche deutsche Puenktlichkeit!\nA: Ist das wirklich wahr?\nB: Meistens. Es ist sprichwörtlich geworden.",exampleSrc:"A: Germans are proverbially punctual.\nB: Yes, the proverbial German punctuality!\nA: Is that really true?\nB: Mostly. It has become proverbial.",funFact:"When something is so well-known it has become like a proverb. 'Die sprichwörtliche deutsche Puenktlichkeit' (the proverbial German punctuality). Also: 'sprichwörtlich ins Fettnäpfchen treten' (proverbially putting your foot in it)."},
{type:"teach",trg:"zweideutig",src:"ambiguous, double-meaning",pos:"adj",gender:null,note:"'Zwei' (two) + 'deutig' (meaning). Having two interpretations.\n'Ein zweideutiger Witz' (an ambiguous joke).",example:"A: Dieses Sprichwort ist zweideutig.\nB: Ja, es hat zwei Bedeutungen.\nA: Welche meinst du?\nB: Beide! Das ist das Schoene an zweideutigen Ausdrücken.",exampleSrc:"A: This proverb is ambiguous.\nB: Yes, it has two meanings.\nA: Which one do you mean?\nB: Both! That is the beauty of ambiguous expressions.",funFact:"From 'zwei' (two) + 'deutig' (meaning). Many Sprichwörter are deliberately zweideutig, carrying a surface meaning and a deeper one. 'Eindeutig' (unambiguous) is the opposite."},
{type:"teach",trg:"umgangssprachlich",src:"colloquial, informal",pos:"adj",gender:null,note:"'Umgang' (interaction) + 'sprachlich' (linguistic).\nThe register of everyday speech.",example:"A: Ist 'cool' umgangssprachlich?\nB: Ja, das ist umgangssprachlich.\nA: Und 'ausgezeichnet'?\nB: Das ist formeller. Nicht umgangssprachlich.",exampleSrc:"A: Is 'cool' colloquial?\nB: Yes, that is colloquial.\nA: And 'ausgezeichnet'?\nB: That is more formal. Not colloquial.",funFact:"The register of everyday speech. 'Umgangssprachlich sagt man...' (colloquially, one says...) introduces informal alternatives. Many Redewendungen are umgangssprachlich. Academic writing avoids them."},
{type:"teach",trg:"gleichnishaft",src:"parable-like, allegorical",pos:"adj",gender:null,note:"'Gleichnis' (parable) + '-haft' (having the quality of).\nDescribes stories with deeper meaning.",example:"A: Heinrichs Geschichten sind gleichnishaft.\nB: Ja, sie haben immer eine tiefere Bedeutung.\nA: Wie ein Gleichnis aus der Bibel?\nB: Aehnlich. Einfach an der Oberfläche, tief darunter.",exampleSrc:"A: Heinrich's stories are parable-like.\nB: Yes, they always have a deeper meaning.\nA: Like a parable from the Bible?\nB: Similar. Simple on the surface, deep beneath.",funFact:"Heinrich's bakery stories are gleichnishaft: simple tales about bread and flour that carry wisdom about life. The '-haft' suffix means 'having the quality of,' like English '-ish' or '-like.'"},
{type:"match",pairs:[{trg:"sprichwörtlich",src:"proverbial"},{trg:"zweideutig",src:"ambiguous, double-meaning"},{trg:"umgangssprachlich",src:"colloquial, informal"},{trg:"gleichnishaft",src:"parable-like, allegorical"}]},
{type:"teach",trg:"prosaisch",src:"prosaic, unimaginative",pos:"adj",gender:null,note:"From 'Prosa' (prose) + '-isch.'\nDouble meaning: belonging to prose (neutral) or being dull (negative).",example:"A: Das klingt etwas prosaisch.\nB: Ja, es fehlt die Poesie.\nA: Kannst du es poetischer sagen?\nB: Statt 'Es regnet' vielleicht 'Der Himmel weint.'",exampleSrc:"A: That sounds rather prosaic.\nB: Yes, it lacks poetry.\nA: Can you say it more poetically?\nB: Instead of 'It is raining' perhaps 'The sky weeps.'",funFact:"A word with two faces. In literary theory, 'prosaisch' simply means 'in prose' (neutral). In everyday speech, it means 'unimaginative' or 'dull' (negative). Context decides which meaning applies."},
{type:"teach",trg:"sprachlich",src:"linguistic, language-related",pos:"adj",gender:null,note:"'Sprache' (language) + '-lich.' Used in literary analysis.\n'Sprachliche Mittel' (linguistic devices).",example:"A: Welche sprachlichen Mittel benutzt Heinrich?\nB: Metaphern, Vergleiche und Sprichwörter.\nA: Er ist sprachlich sehr begabt.\nB: Ja, ein natürlicher Erzähler.",exampleSrc:"A: What linguistic devices does Heinrich use?\nB: Metaphors, comparisons, and proverbs.\nA: He is linguistically very gifted.\nB: Yes, a natural storyteller.",funFact:"'Sprachliche Mittel' (linguistic devices) is the standard term in German literary analysis. 'Sprachlich begabt' (linguistically talented) is high praise. From 'Sprache' (language) + '-lich.'"},
{type:"mc",q:"Heinrichs Geschichten haben immer eine tiefere Bedeutung. Sie sind...?",opts:["gleichnishaft","prosaisch","ironisch","satirisch"],ans:"gleichnishaft",hint:"Like a parable with a hidden lesson. The suffix '-haft' means having the quality of something."},
{type:"fb",s:"Der Text klingt etwas {1}. Es fehlt die Poesie.",a:["prosaisch"],opts:["prosaisch","sprachlich","gleichnishaft","übertragen"],hint:"From 'Prosa' (prose). In everyday speech it means dull or lacking imagination.",sSrc:"The text sounds a bit prosaic. It lacks poetry."}
]},
{id:"deu_r28l5b",title:"Laut Heinrich (Teil 2)",icon:"\uD83D\uDCDC",xp:15,board:true,steps:[
{type:"intro",title:"Laut Heinrich (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"schriftlich",src:"written, in writing",pos:"adj",gender:null,note:"'Schrift' (writing) + '-lich.' The opposite of 'mündlich.'\n'Bitte bestätigen Sie schriftlich' (please confirm in writing).",example:"A: Ist die Prüfung schriftlich oder mündlich?\nB: Schriftlich. Du musst einen Aufsatz schreiben.\nA: Und die schriftliche Überlieferung?\nB: Die begann erst, als jemand Sprichwörter aufschrieb.",exampleSrc:"A: Is the exam written or oral?\nB: Written. You have to write an essay.\nA: And the written tradition?\nB: That only began when someone wrote proverbs down.",funFact:"'Schriftliche Überlieferung' (written tradition) is how stories survive on paper. The opposite of 'mündlich.' 'Bitte bestätigen Sie schriftlich' (please confirm in writing) is standard German bureaucracy."},
{type:"teach",trg:"mündlich",src:"oral, verbal",pos:"adj",gender:null,note:"'Mund' (mouth) + '-lich.' The opposite of 'schriftlich.'\n'Mündliche Überlieferung' (oral tradition).",example:"A: Sprichwörter wurden mündlich überliefert.\nB: Ja, von Generation zu Generation.\nA: Ohne Buecher?\nB: Genau. Nur durch mündliche Weitergabe.",exampleSrc:"A: Proverbs were passed down orally.\nB: Yes, from generation to generation.\nA: Without books?\nB: Exactly. Only through oral transmission.",funFact:"'Mündliche Überlieferung' (oral tradition) is how Sprichwörter survived for centuries before anyone wrote them down. 'Mündliche Prüfung' (oral exam). Through the mouth, not on paper."},
{type:"teach",trg:"übertragen",src:"figurative, transferred",pos:"adj",gender:null,note:"Past participle of 'übertragen' (to transfer).\n'Im übertragenen Sinn' (in the figurative sense).",example:"A: Was ist die übertragene Bedeutung?\nB: Die Bedeutung jenseits der Worte.\nA: Also nicht wörtlich?\nB: Genau. Übertragen heißt: vom Wörtlichen ins Bildliche.",exampleSrc:"A: What is the figurative meaning?\nB: The meaning beyond the words.\nA: So not literal?\nB: Exactly. Transferred means: from literal to figurative.",funFact:"When meaning is 'carried over' from literal to symbolic. 'Übertragene Bedeutung' = figurative meaning. The prefix 'über' (over) + 'tragen' (to carry) creates a word about meaning crossing boundaries."},
{type:"teach",trg:"äußern",src:"to express, to utter",pos:"verb",gender:null,note:"From 'äußer' (outer). Making inner thoughts outer.\nReflexive: 'sich äußern zu' (to comment on). Not separable.",example:"A: Moechtest du deine Meinung äußern?\nB: Ja, ich möchte mich dazu äußern.\nA: Dann äußere dich frei.\nB: Heinrich äußerte oft Weisheiten beim Kaffee.",exampleSrc:"A: Would you like to express your opinion?\nB: Yes, I would like to comment on that.\nA: Then express yourself freely.\nB: Heinrich often uttered wisdom over coffee.",funFact:"Making inner thoughts outer. From 'äußer' (outer). Reflexive: 'sich äußern zu' (to comment on). 'Er äußerte seine Meinung' (He expressed his opinion). Not separable."},
{type:"teach",trg:"einraeumen",src:"to concede, to admit",pos:"verb",gender:null,note:"'Ein' (in) + 'raeumen' (from 'Rahmen,' frame). Separable.\nMaking room for the other side's point.",example:"A: Raeumst du ein, dass es schwer war?\nB: Ja, ich raeume ein, dass der Anfang hart war.\nA: Aber du hast durchgehalten.\nB: Das raeume ich gerne ein.",exampleSrc:"A: Do you concede that it was hard?\nB: Yes, I concede that the beginning was tough.\nA: But you persevered.\nB: I gladly concede that.",funFact:"'Ein' (in) + 'raeumen' (to make room). Making room for the other side's point. Separable: 'Er raeumte ein, dass die Zeiten hart waren.' More formal than 'zugeben' (to admit)."},
{type:"match",pairs:[{trg:"mündlich",src:"oral, verbal"},{trg:"übertragen",src:"figurative, transferred"},{trg:"äußern",src:"to express, to utter"},{trg:"einraeumen",src:"to concede, to admit"}]},
{type:"teach",trg:"hinzufügen",src:"to add (to what was said)",pos:"verb",gender:null,note:"'Hinzu' (in addition) + 'fuegen' (to join). Separable.\n'Er fuegte hinzu, dass...' (He added that...).",example:"A: Moechtest du etwas hinzufügen?\nB: Ja, ich möchte hinzufügen, dass Heinrich recht hatte.\nA: Was fuegte er noch hinzu?\nB: Er fuegte hinzu, dass Brot alles bedeute.",exampleSrc:"A: Would you like to add something?\nB: Yes, I would like to add that Heinrich was right.\nA: What else did he add?\nB: He added that bread meant everything.",funFact:"Adding something to what has already been said. Separable: 'Er fuegte hinzu, dass...' The 'hinzu' prefix means 'in addition to.' 'Hinzufuegung' is the noun form."},
{type:"teach",trg:"mitteilen",src:"to inform, to communicate",pos:"verb",gender:null,note:"'Mit' (with) + 'teilen' (to share). Separable.\n'Er teilte mir mit, dass...' (He informed me that...).",example:"A: Ich möchte dir etwas mitteilen.\nB: Was willst du mir mitteilen?\nA: Heinrich hat mir mitgeteilt, dass er nächssten Sonntag wiederkommt.\nB: Das ist eine schoene Mitteilung!",exampleSrc:"A: I would like to inform you of something.\nB: What do you want to tell me?\nA: Heinrich informed me that he is coming back next Sunday.\nB: That is nice news!",funFact:"Sharing information with someone. 'Mit' (with) + 'teilen' (to share/divide). Separable: 'Er teilte mir mit, dass...' 'Mitteilung' (notification, message) is the noun. More formal than simply 'sagen.'"},
{type:"teach",trg:"anmerken",src:"to remark, to note",pos:"verb",gender:null,note:"'An' (at) + 'merken' (to notice). Separable.\nLighter than 'betonen' (to emphasize).",example:"A: Darf ich etwas anmerken?\nB: Natürlich, merk es an.\nA: Heinrich merkte an, dass frühes Aufstehen wichtig sei.\nB: Eine gute Anmerkung.",exampleSrc:"A: May I remark on something?\nB: Of course, go ahead.\nA: Heinrich remarked that getting up early was important.\nB: A good remark.",funFact:"Making a note of something in conversation. 'An' (at) + 'merken' (to notice/mark). Separable: 'Er merkte an, dass...' Lighter than 'betonen' (to emphasize). 'Anmerkung' (remark, annotation) is the noun."},
{type:"tip",title:"Indirekte Rede: Tempuswechsel",text:"Reported speech in Konjunktiv I follows three tense-shift rules.\n\n- Present tense in direct speech shifts to Konjunktiv I present: 'Die Backstube IST wunderbar' becomes 'Er sagte, die Backstube SEI wunderbar.'\n- Past tense shifts to Konjunktiv I past, using habe or sei plus Partizip II: 'Ich HABE um vier angefangen' becomes 'Er sagte, er HABE um vier angefangen.'\n- Future tense shifts to Konjunktiv I future, using werde plus Infinitiv: 'Ich WERDE weitermachen' becomes 'Er sagte, er WERDE weitermachen.'\n\nThe Konjunktiv I operates in its own tense system, independent of the tense of the reporting verb.",deepDive:{title:"Why tense shifts?",text:"In the indicative, you often shift into the Präteritum when reporting. The Konjunktiv I, by contrast, has its own three-tense system: present (sage), past (habe gesagt), future (werde sagen). This system is independent of whether the reporting verb is in the Präteritum or Perfekt. 'Heinrich sagte, die Backstube sei wunderbar' and 'Heinrich hat gesagt, die Backstube sei wunderbar' mean the same thing."}},
{type:"verb_table",title:"Indirekte Rede: Tempuswechsel",groups:[{label:"Gegenwart (gegenwärtig berichtet)",rows:[{pronoun:"Direkt",form:"'Die Backstube ist wunderbar.'",src:"The bakery is wonderful."},{pronoun:"Indirekt",form:"Er sagte, die Backstube sei wunderbar.",src:"He said the bakery was wonderful."}]},{label:"Vergangenheit (vergangen berichtet)",rows:[{pronoun:"Direkt",form:"'Ich habe um vier angefangen.'",src:"I started at four."},{pronoun:"Indirekt",form:"Er sagte, er habe um vier angefangen.",src:"He said he had started at four."}]},{label:"Futur (zukuenftig berichtet)",rows:[{pronoun:"Direkt",form:"'Ich werde weitermachen.'",src:"I will continue."},{pronoun:"Indirekt",form:"Er sagte, er werde weitermachen.",src:"He said he would continue."}]}]},
{type:"mc",q:"Direkt: 'Ich habe die Baeckerei 1960 eröffnet.' Indirekt: 'Er sagte, er habe die Baeckerei 1960 eröffnet.' Welcher Tempuswechsel hat stattgefunden?",opts:["Perfekt wurde zu Konjunktiv I Vergangenheit (habe + Partizip)","Perfekt blieb in der indirekten Rede unverändert","Perfekt wurde direkt in eine Präteritumform verwandelt","Perfekt wurde zu einer Konjunktiv-II-Gegenwartsform umgewandelt"],ans:"Perfekt wurde zu Konjunktiv I Vergangenheit (habe + Partizip)",hint:"In indirect speech, past tense shifts to a special subjunctive form. The helping verb takes a new subjunctive ending while the past content is preserved."},
{type:"fb",s:"Heinrich sagte, er {1} jeden Morgen früh auf.",a:["stehe"],opts:["steht","stehe","stand","stunde"],hint:"Present tense in direct speech becomes Konjunktiv I Gegenwart in indirect speech.",sSrc:"Heinrich said he gets up early every morning."},
{type:"mc",q:"'Heinrich berichtete, die Backstube sei wunderbar gewesen. Er erzählte es, als hätte er sie nie verlassen. Er betonte, er wolle die Erinnerung bewahren.' Wie viele Grammatikkonstrukte?",opts:["Zwei: Konjunktiv I Gegenwart zusammen mit Konjunktiv II","Drei: Konj. I Vergangenheit + als + Konj. II + Konj. I Gegenwart","Eins: nur eine einzige einfache Konjunktiv-I-Form","Zwei: Konjunktiv I Gegenwart und als-ob-Konstruktion mit Konjunktiv II"],ans:"Drei: Konj. I Vergangenheit + als + Konj. II + Konj. I Gegenwart",hint:"Count the distinct grammatical moods in the three reported sentences. Two are reporting moods, one is a comparison mood. Are they all the same or different?"},
{type:"drag_fill",s:"Heinrich erzählte, sein Großvater {1} immer gesagt, Brot {2} das Wichtigste.",blanks:{"1":"habe","2":"sei"},pool:["habe","sei","hat","ist","hatte","wäre"],hint:"The first blank reports a past action in indirect speech; the second reports a timeless truth. Two different tenses of the same reporting mood.",sSrc:"Heinrich told that his grandfather had always said bread was the most important thing."},
{type:"match",pairs:[{trg:"behaupten",src:"to claim"},{trg:"betonen",src:"to emphasize"},{trg:"einraeumen",src:"to concede"},{trg:"anmerken",src:"to remark"}]},
{type:"mc",q:"Was bedeutet 'schriftlich'?",opts:["colloquial, informal","figurative, metaphorical","written, in writing","to inform, to communicate"],ans:"written, in writing",hint:"From Schrift (script/text). The -lich suffix makes it an adjective: 'in that form'."},
{type:"fb",s:"Sprichwörter wurden {1} überliefert.",a:["mündlich"],opts:["mündlich","schriftlich","hinzufügen","im übertragenen Sinne"],hint:"From Mund (mouth). The opposite of 'in writing' -- passed down by word of mouth.",sSrc:"Proverbs were passed down orally."},
{type:"mc",q:"Was bedeutet 'äußern'?",opts:["to concede, to admit","linguistic, language-related","figurative, metaphorical","to express, to utter"],ans:"to express, to utter",hint:"From äußer- (outer/external). To bring inner thoughts to the outside."},
{type:"fb",s:"Moechtest du etwas {1}?",a:["hinzufügen"],opts:["hinzufügen","zweideutig","still","wörtlich"],hint:"A separable verb: hinzu (in addition) + fügen (to join). To append something extra.",sSrc:"Would you like to add something?"},
{type:"mc",q:"Was bedeutet 'mitteilen'?",opts:["to inform, to communicate","literal, word-for-word","colloquial, informal","the beginning"],ans:"to inform, to communicate",hint:"Compound: mit (with) + teilen (to share). To share news or facts with someone."}
]},
{id:"deu_r28l6",title:"Morgenstund hat Gold im Mund",icon:"\u2600\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Morgenstund hat Gold im Mund",desc:"Learn the most important German proverbs. Practice all three grammar constructs in literary contexts. Understand proverbs as cultural values.",goals:["Learn the most important German proverbs","Practice all three grammar constructs in literary contexts","Understand proverbs as expressions of cultural values"]},
{type:"teach",trg:"Morgenstund hat Gold im Mund",src:"The early bird catches the worm (lit: the morning hour has gold in its mouth)",pos:"intj",gender:null,note:"Ancient German proverb praising early rising.\nArchaic form: 'Morgenstund' instead of 'Morgenstunde.'",example:"A: Warum stehst du so früh auf?\nB: Morgenstund hat Gold im Mund!\nA: Das sagt mein Großvater auch immer.\nB: Grossvaeter haben meistens recht.",exampleSrc:"A: Why do you get up so early?\nB: The morning hour has gold in its mouth!\nA: My grandfather always says that too.\nB: Grandfathers are usually right.",funFact:"Dating back centuries. 'Morgenstund' is an archaic form of 'Morgenstunde.' Gold in the mouth: the morning speaks richly. The German equivalent of 'The early bird catches the worm,' but far more poetic."},
{type:"teach",trg:"Übung macht den Meister",src:"Practice makes perfect (lit: practice makes the master)",pos:"intj",gender:null,note:"One of Germany's most used proverbs.\nNote: 'Meister' (master), not 'perfekt' (perfect).",example:"A: Ich kann das noch nicht gut.\nB: Übung macht den Meister!\nA: Wie oft muss ich üben?\nB: Jeden Tag. Der Meister fällt nicht vom Himmel.",exampleSrc:"A: I cannot do that well yet.\nB: Practice makes the master!\nA: How often do I have to practice?\nB: Every day. The master does not fall from the sky.",funFact:"The German version says 'Meister' (master), not 'perfect.' You can always keep learning. German humility: even mastery is a journey, not a destination. Paired with 'Es ist noch kein Meister vom Himmel gefallen.'"},
{type:"teach",trg:"Aller Anfang ist schwer",src:"Every beginning is difficult",pos:"intj",gender:null,note:"Universal comfort for starting something new.\nGermans cite it when things start badly.",example:"A: Ich verstehe diese Grammatik nicht.\nB: Aller Anfang ist schwer.\nA: Das hilft mir gerade nicht.\nB: Doch! Es wird leichter. Versprochen.",exampleSrc:"A: I do not understand this grammar.\nB: Every beginning is difficult.\nA: That does not help me right now.\nB: It does! It gets easier. Promise.",funFact:"Universal comfort for anyone starting something new. Every language learner knows this truth. Encouragement disguised as resignation. The proverb validates the struggle."},
{type:"teach",trg:"Reden ist Silber, Schweigen ist Gold",src:"Speech is silver, silence is gold",pos:"intj",gender:null,note:"Praises knowing when NOT to speak.\nVery German: restraint valued over expression.",example:"A: Soll ich etwas dazu sagen?\nB: Manchmal ist Reden Silber und Schweigen Gold.\nA: Du meinst, ich soll still sein?\nB: Ich meine, nicht jeder Gedanke braucht Worte.",exampleSrc:"A: Should I say something about it?\nB: Sometimes speech is silver and silence is gold.\nA: You mean I should be quiet?\nB: I mean not every thought needs words.",funFact:"Praises the value of knowing when NOT to speak. Very German: restraint valued over expression. Used when someone talks too much or too impulsively. Silver is valuable, but gold is worth more."},
{type:"teach",trg:"Man soll den Tag nicht vor dem Abend loben",src:"Do not count your chickens before they hatch (lit: one should not praise the day before the evening)",pos:"intj",gender:null,note:"German caution against premature celebration.\nWait for the outcome before judging.",example:"A: Ich glaube, ich habe die Prüfung bestanden!\nB: Man soll den Tag nicht vor dem Abend loben.\nA: Du meinst, ich soll noch warten?\nB: Warte auf das Ergebnis. Dann kannst du feiern.",exampleSrc:"A: I think I passed the exam!\nB: One should not praise the day before the evening.\nA: You mean I should wait?\nB: Wait for the result. Then you can celebrate.",funFact:"Do not celebrate too early. Wait for the outcome. German caution: success is only real when the day is done. Similar to 'Do not count your chickens before they hatch.'"},
{type:"mc",q:"Welches Sprichwort warnt davor, zu frueh zu feiern?",opts:["Man soll den Tag nicht vor dem Abend loben","Reden ist Silber, Schweigen ist Gold","Uebung macht den Meister","Aller Anfang ist schwer"],ans:"Man soll den Tag nicht vor dem Abend loben",hint:"Wait for the day to end before judging it. Do not celebrate until the outcome is clear."}
]},
{id:"deu_r28l6b",title:"Morgenstund hat Gold im Mund (Teil 2)",icon:"\u2600\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Morgenstund hat Gold im Mund (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"Es ist noch kein Meister vom Himmel gefallen",src:"Nobody is born an expert (lit: no master has yet fallen from the sky)",pos:"intj",gender:null,note:"Mastery requires work. Nobody starts perfect.\nCompanion to 'Übung macht den Meister.'",example:"A: Ich bin so schlecht darin!\nB: Es ist noch kein Meister vom Himmel gefallen.\nA: Meinst du, ich kann es lernen?\nB: Natürlich! Jeder Meister war mal Anfaenger.",exampleSrc:"A: I am so bad at this!\nB: No master has yet fallen from the sky.\nA: Do you think I can learn it?\nB: Of course! Every master was once a beginner.",funFact:"Nobody is born an expert. Mastery requires work. The companion to 'Übung macht den Meister.' Together they form a philosophy: practice patiently, nobody starts perfect."},
{type:"teach",trg:"Wer zuletzt lacht, lacht am besten",src:"Whoever laughs last laughs best",pos:"intj",gender:null,note:"Patience wins. The long game matters.\nGerman love of delayed gratification.",example:"A: Sie haben über mich gelacht.\nB: Wer zuletzt lacht, lacht am besten.\nA: Das stimmt. Ich werde es ihnen zeigen.\nB: Genau. Geduld zahlt sich aus.",exampleSrc:"A: They laughed at me.\nB: Whoever laughs last laughs best.\nA: That is true. I will show them.\nB: Exactly. Patience pays off.",funFact:"The early mockers may regret it. German love of the long game: the final outcome matters more than the initial reaction. Patience and persistence are deeply German values."},
{type:"teach",trg:"Andere Laender, andere Sitten",src:"Different countries, different customs",pos:"intj",gender:null,note:"Acknowledges cultural differences.\nNot judgmental but observational.",example:"A: In meinem Land machen wir das anders.\nB: Andere Laender, andere Sitten!\nA: Genau. Keins ist besser oder schlechter.\nB: Nur anders. Und anders ist interessant.",exampleSrc:"A: In my country we do that differently.\nB: Different countries, different customs!\nA: Exactly. Neither is better or worse.\nB: Just different. And different is interesting.",funFact:"The German acknowledgment that cultures differ. Used when something foreign seems strange. Not judgmental but observational. Verumius has lived this proverb every day since arriving in Germany."},
{type:"teach",trg:"Wer A sagt, muss auch B sagen",src:"If you start something, follow through (lit: whoever says A must also say B)",pos:"intj",gender:null,note:"Commitment and follow-through.\nGerman consistency culture.",example:"A: Ich habe angefangen, aber es ist schwer.\nB: Wer A sagt, muss auch B sagen.\nA: Du meinst, ich muss weitermachen?\nB: Du hast dich entschieden. Jetzt zieh es durch.",exampleSrc:"A: I started but it is hard.\nB: Whoever says A must also say B.\nA: You mean I have to continue?\nB: You made your decision. Now follow through.",funFact:"If you start something, see it through. German consistency culture: do not begin what you cannot finish. Once you commit, the alphabet demands you continue."},
{type:"teach",trg:"Der Apfel fällt nicht weit vom Stamm",src:"The apple does not fall far from the tree",pos:"intj",gender:null,note:"Children resemble their parents.\nHeinrich's favorite proverb.",example:"A: Du backst genau wie dein Vater!\nB: Der Apfel fällt nicht weit vom Stamm.\nA: Das stimmt bei dir wirklich.\nB: Ich habe alles von ihm gelernt.",exampleSrc:"A: You bake just like your father!\nB: The apple does not fall far from the tree.\nA: That really is true for you.\nB: I learned everything from him.",funFact:"Heinrich's favorite: he became a baker like his grandfather. The Stamm (tree trunk) represents family roots. Nearly identical to the English version."},
{type:"match",pairs:[{trg:"Wer zuletzt lacht, lacht am besten",src:"Whoever laughs last laughs best"},{trg:"Andere Laender, andere Sitten",src:"Different countries, different customs"},{trg:"Wer A sagt, muss auch B sagen",src:"If you start something, follow through (lit: whoever says A must also say B)"},{trg:"Der Apfel fällt nicht weit vom Stamm",src:"The apple does not fall far from the tree"}]},
{type:"teach",trg:"Stille Wasser sind tief",src:"Still waters run deep",pos:"intj",gender:null,note:"Quiet people may have hidden depth.\nGerman respect for introversion.",example:"A: Er sagt nie viel.\nB: Stille Wasser sind tief.\nA: Du meinst, er denkt viel nach?\nB: Die Stillen haben oft die tiefsten Gedanken.",exampleSrc:"A: He never says much.\nB: Still waters run deep.\nA: You mean he thinks a lot?\nB: The quiet ones often have the deepest thoughts.",funFact:"A warning: do not underestimate the silent ones. Quiet people may have deep thoughts or hidden complexity. German respect for introversion. Nearly identical in English and German."},
{type:"teach",trg:"Wo ein Wille ist, ist auch ein Weg",src:"Where there is a will, there is a way",pos:"intj",gender:null,note:"Determination creates solutions.\nThe same proverb exists in English.",example:"A: Ich weiß nicht, wie ich das schaffen soll.\nB: Wo ein Wille ist, ist auch ein Weg.\nA: Meinst du wirklich?\nB: Immer. Der Wille findet den Weg.",exampleSrc:"A: I do not know how I am supposed to manage this.\nB: Where there is a will, there is a way.\nA: Do you really think so?\nB: Always. The will finds the way.",funFact:"Determination creates solutions. The same proverb exists in English. Universal human truth: willpower overcomes obstacles. One of the few German proverbs with an exact English equivalent."},
{type:"teach",trg:"der Daumen",src:"the thumb",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Daumen.\n'Jemandem die Daumen drücken' (to wish luck).",example:"A: Ich habe morgen eine Prüfung.\nB: Ich drücke dir die Daumen!\nA: Danke! Daumen drücken hilft immer.\nB: Na dann, alle Daumen sind gedrückt!",exampleSrc:"A: I have an exam tomorrow.\nB: I am pressing my thumbs for you!\nA: Thanks! Pressing thumbs always helps.\nB: Well then, all thumbs are pressed!",funFact:"'Jemandem die Daumen drücken' (to press thumbs for someone) is the German way of wishing luck. Not crossing fingers. Pressing thumbs. Physical gesture: fists with thumbs tucked inside."},
{type:"teach",trg:"der Hals",src:"the neck, the throat",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Haelse.\n'Hals- und Beinbruch!' (Break a leg!).",example:"A: Ich bin so nervoes vor dem Auftritt.\nB: Hals- und Beinbruch!\nA: Das klingt nicht nett!\nB: Doch! Es bedeutet 'Viel Glück!' auf Deutsch.",exampleSrc:"A: I am so nervous before the performance.\nB: Break your neck and leg!\nA: That does not sound nice!\nB: It does! It means 'Good luck!' in German.",funFact:"'Hals- und Beinbruch!' (Neck and leg break!) means 'Break a leg!' German superstition: wishing bad luck to bring good luck. Ironic protection against fate."},
{type:"teach",trg:"die Haut",src:"the skin",pos:"noun",gender:"f",note:"Feminine noun. 'Mit Haut und Haar' means completely.\n'Er hat sich mit Haut und Haar verschrieben.'",example:"A: Er hat sich mit Haut und Haar der Baeckerei verschrieben.\nB: Ja, mit Haut und Haar!\nA: Was bedeutet das genau?\nB: Ganz und gar. Vollständig. Mit allem, was er hat.",exampleSrc:"A: He devoted himself completely to the bakery.\nB: Yes, with skin and hair!\nA: What does that mean exactly?\nB: Entirely. Completely. With everything he has.",funFact:"'Mit Haut und Haar' (with skin and hair) means completely, entirely. Body idioms are vivid in German. The Haut is the boundary between inside and outside, self and world."},
{type:"match",pairs:[{trg:"Wo ein Wille ist, ist auch ein Weg",src:"Where there is a will, there is a way"},{trg:"der Daumen",src:"the thumb"},{trg:"der Hals",src:"the neck, the throat"},{trg:"die Haut",src:"the skin"}]},
{type:"teach",trg:"der Kopf",src:"the head",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Koepfe.\n'Kopf hoch!' (Head up! / Chin up!).",example:"A: Ich habe die Prüfung nicht bestanden.\nB: Kopf hoch! Das nächsste Mal klappt es.\nA: Meinst du?\nB: Ja. Steck den Kopf nicht in den Sand.",exampleSrc:"A: I did not pass the exam.\nB: Head up! Next time it will work.\nA: Do you think so?\nB: Yes. Do not stick your head in the sand.",funFact:"'Den Kopf in den Sand stecken' (to stick your head in the sand) means to ignore problems. 'Kopf hoch!' (Head up!) is encouragement. The head hosts dozens of German Redewendungen."},
{type:"teach",trg:"der Nagel",src:"the nail",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Naegel.\n'Den Nagel auf den Kopf treffen' (to hit the nail on the head).",example:"A: Das war genau richtig!\nB: Du hast den Nagel auf den Kopf getroffen.\nA: Wirklich?\nB: Ja, genau ins Schwarze. Perfekt formuliert.",exampleSrc:"A: That was exactly right!\nB: You hit the nail on the head.\nA: Really?\nB: Yes, right on target. Perfectly expressed.",funFact:"Two idioms: 'Etwas auf den Nagel haengen' (to hang something on a nail) means to quit. 'Den Nagel auf den Kopf treffen' (to hit the nail on the head) means to be exactly right. Same noun, different wisdom."},
{type:"teach",trg:"der Stamm",src:"the trunk, the stem",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Staemme.\nFamily roots: 'Der Apfel fällt nicht weit vom Stamm.'",example:"A: Der Stamm des Baumes ist sehr dick.\nB: Ja, alte Baeume haben dicke Staemme.\nA: Und der Familienstamm?\nB: Der Apfel fällt nicht weit vom Stamm.",exampleSrc:"A: The trunk of the tree is very thick.\nB: Yes, old trees have thick trunks.\nA: And the family tree?\nB: The apple does not fall far from the trunk.",funFact:"'Stammtisch' (regular table at a pub), 'Stammkunde' (regular customer), 'Stammbaum' (family tree). The trunk from which branches grow. The Stamm is roots, tradition, belonging."},
{type:"teach",trg:"der Schmetterling",src:"the butterfly",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Schmetterlinge.\n'Schmetterlinge im Bauch' (butterflies in the stomach).",example:"A: Hast du Schmetterlinge im Bauch?\nB: Ja, ich bin so aufgeregt!\nA: Das ist normal vor dem ersten Treffen.\nB: Tausend Schmetterlinge!",exampleSrc:"A: Do you have butterflies in your stomach?\nB: Yes, I am so excited!\nA: That is normal before the first meeting.\nB: A thousand butterflies!",funFact:"'Schmetterlinge im Bauch haben' (to have butterflies in your stomach) means to be in love or nervously excited. The German word comes from 'Schmetten' (cream), because butterflies were thought to steal cream."},
{type:"teach",trg:"versinnbildlichen",src:"to symbolize, to represent",pos:"verb",gender:null,note:"'Ver-' + 'Sinnbild' (symbol) + '-lichen.' Not separable.\nThe most literary verb for expressing symbolic meaning.",example:"A: Was versinnbildlicht das Brot in Heinrichs Geschichten?\nB: Brot versinnbildlicht Gemeinschaft und Tradition.\nA: Und die Baeckerei?\nB: Die versinnbildlicht sein Lebenswerk.",exampleSrc:"A: What does bread symbolize in Heinrich's stories?\nB: Bread symbolizes community and tradition.\nA: And the bakery?\nB: That symbolizes his life's work.",funFact:"'Ver-' + 'Sinnbild' (symbol) + '-lichen.' Not separable. The most literary verb for expressing symbolic meaning. 'Brot versinnbildlicht Gemeinschaft' (Bread symbolizes community)."},
{type:"fb",s:"Er hat sich mit {1} und Haar der Baeckerei verschrieben. Das heisst: vollstaendig.",a:["Haut"],opts:["Haut","Kopf","Nagel","Hals"],hint:"Feminine noun for the body's outer covering. The idiom means completely, entirely.",sSrc:"He devoted himself completely to the bakery. That means: entirely."},
{type:"mc",q:"Heinrich sagt: 'Man soll den Tag nicht vor dem Abend loben.' Er meint...",opts:["Feiere nicht zu früh, warte das Ergebnis ab","Abende sind grundsätzlich besser als Morgen","Man sollte frühestens abends über Erfolge sprechen","Lobe immer den Morgen und nie den Abend"],ans:"Feiere nicht zu früh, warte das Ergebnis ab",hint:"Wait until the day is over before judging it. German caution against premature celebration."},
{type:"fb",s:"Heinrich sagte, wer A sage, {1} auch B sagen.",a:["müsse"],opts:["müsse","muss","müsste","müssten"],hint:"Indirect speech requires Konjunktiv I. Select the Konjunktiv I third-person singular form of the modal verb expressing necessity.",sSrc:"Heinrich said whoever says A must also say B."},
{type:"mc",q:"'Heinrich berichtete, die Baeckerei sei wunderbar gewesen. Er sprach darüber, als ob er noch dort arbeiten würde.' Welche Konstrukte?",opts:["Indikativ direkt kombiniert mit Konjunktiv I","Konjunktiv I + als ob + Konjunktiv II","Beides nur Konjunktiv I","Beides nur Konjunktiv II"],ans:"Konjunktiv I + als ob + Konjunktiv II",hint:"The two sentences use different verb moods. One reports a fact from someone's mouth; the other describes a scenario that does not reflect current reality."},
{type:"drag_fill",s:"Heinrich erzählte, sein Großvater {1} immer gesagt, Übung {2} den Meister.",blanks:{"1":"habe","2":"mache"},pool:["habe","mache","hat","macht","hatte","machte"],hint:"Two blanks, two tenses of reported speech. The first reports a past act; the second reports a timeless proverb truth. Both use the reporting mood.",sSrc:"Heinrich told that his grandfather had always said practice makes the master."},
{type:"match",pairs:[{trg:"Morgenstund hat Gold im Mund",src:"The early bird catches the worm"},{trg:"Aller Anfang ist schwer",src:"Every beginning is difficult"},{trg:"Übung macht den Meister",src:"Practice makes perfect"},{trg:"Stille Wasser sind tief",src:"Still waters run deep"}]},
{type:"mc",q:"Was bedeutet 'Es ist noch kein Meister vom Himmel gefallen'?",opts:["the head","Where there is a will, there is a way","Nobody is born an expert (lit: no master has yet fallen from the sky)","If you start something, follow through (lit: whoever says A must also say B)"],ans:"Nobody is born an expert (lit: no master has yet fallen from the sky)",hint:"A proverb about earning skill through practice, not luck or talent alone."},
{type:"fb",s:"{1}!",a:["Andere Laender, andere Sitten"],opts:["der Stamm","Es ist noch kein Meister vom Himmel gefallen","Morgenstund hat Gold im Mund","Andere Laender, andere Sitten"],hint:"The proverb about cultural differences. Each place has its own norms and traditions.",sSrc:"Different countries, different customs!"},
{type:"mc",q:"Was bedeutet 'Der Apfel fällt nicht weit vom Stamm'?",opts:["Still waters run deep","Practice makes perfect (lit: practice makes the master)","the thumb","The apple does not fall far from the tree"],ans:"The apple does not fall far from the tree",hint:"Apfel = the fruit; Stamm = trunk/stem. Children resemble their parents."},
{type:"fb",s:"{1}.",a:["Wo ein Wille ist, ist auch ein Weg"],opts:["Wo ein Wille ist, ist auch ein Weg","Aller Anfang ist schwer","Man soll den Tag nicht vor dem Abend loben","Andere Laender, andere Sitten"],hint:"The proverb pairing motivation with its outcome. Determination always finds a solution.",sSrc:"Where there is a will, there is a way."},
{type:"mc",q:"Was bedeutet 'der Daumen'?",opts:["the thumb","Speech is silver, silence is gold","Do not count your chickens before they hatch (lit: one should not praise the day before the evening)","Nobody is born an expert (lit: no master has yet fallen from the sky)"],ans:"the thumb",hint:"The thickest finger. Germans 'press' this finger for good luck (Daumen drücken)."},
{type:"fb",s:"{1} des Baumes ist sehr dick.",a:["der Stamm"],opts:["Übung macht den Meister","Stille Wasser sind tief","der Stamm","der Schmetterling"],hint:"The thick wooden center of a tree. Also means 'tribe' or 'stem' in other contexts.",sSrc:"The trunk of the tree is very thick."},
{type:"mc",q:"Was bedeutet 'der Schmetterling'?",opts:["the trunk, the stem","the butterfly","Different countries, different customs","If you start something, follow through (lit: whoever says A must also say B)"],ans:"the butterfly",hint:"From Schmetten (cream) in old German. A colorful flying insect drawn to dairy."},
{type:"fb",s:"Wie sagt man 'to symbolize, to represent' auf Deutsch? {1}",a:["versinnbildlichen"],opts:["Übung macht den Meister","versinnbildlichen","Stille Wasser sind tief","Man soll den Tag nicht vor dem Abend loben"],hint:"ver- + Sinnbild (symbol) + -lichen. To make something into a symbol.",sSrc:"How do you say 'to symbolize, to represent' in German?"}
]},
{id:"deu_r28l7",title:"Alles auf dem Prüfstand",icon:"\uD83C\uDFAF",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf dem Prüfstand",desc:"Test everything from Unit 28. Prove you can use indirect speech in Konjunktiv I, form unreal comparisons, and use German proverbs correctly.",goals:["Test your knowledge of all constructs from Unit 28","Prove Konjunktiv I, als ob, and proverb competence","Combine all grammar constructs in complex sentences"]},
{type:"teach",trg:"Jemandem die Daumen drücken",src:"to press thumbs for someone (to wish luck)",pos:"intj",gender:null,note:"The German way of wishing luck. Physical gesture:\nfists with thumbs tucked inside.",example:"A: Morgen ist meine grosse Prüfung.\nB: Ich drücke dir die Daumen!\nA: Danke, das brauche ich.\nB: Alle drücken dir die Daumen!",exampleSrc:"A: Tomorrow is my big exam.\nB: I am pressing my thumbs for you!\nA: Thanks, I need that.\nB: Everyone is pressing their thumbs for you!",funFact:"Not crossing fingers. Pressing thumbs. The German gesture of wishing luck. 'Ich drücke dir die Daumen!' is said before exams, job interviews, and first dates."},
{type:"teach",trg:"Etwas auf den Nagel haengen",src:"to give up, to quit (lit: to hang something on a nail)",pos:"intj",gender:null,note:"Finality: once you hang your tools on the nail, you are done.\n'Er hat seinen Beruf an den Nagel gehaengt.'",example:"A: Backst du noch?\nB: Nein, ich habe das Backen an den Nagel gehaengt.\nA: Warum?\nB: Es war Zeit für etwas Neues.",exampleSrc:"A: Do you still bake?\nB: No, I hung up baking.\nA: Why?\nB: It was time for something new.",funFact:"Once you hang your tools on the nail, you are done. Finality. 'Er hat seinen Beruf an den Nagel gehaengt' (He gave up his profession). The nail is the endpoint."},
{type:"teach",trg:"Ins Fettnäpfchen treten",src:"to put your foot in it, to make a social blunder",pos:"intj",gender:null,note:"The Fettnäpfchen was a grease pot by the door.\nStepping in it = social clumsiness.",example:"A: Ich habe seinen Namen falsch ausgesprochen.\nB: Oh nein, du bist ins Fettnäpfchen getreten!\nA: Das war mir so peinlich.\nB: Das passiert jedem mal.",exampleSrc:"A: I mispronounced his name.\nB: Oh no, you stepped into the little grease pot!\nA: That was so embarrassing.\nB: That happens to everyone sometimes.",funFact:"The Fettnäpfchen was a small container of grease kept by the door of old German houses. Stepping in it was clumsy and messy. The image became a metaphor for social blunders."},
{type:"teach",trg:"Auf keinen gruenen Zweig kommen",src:"to never prosper (lit: to never get on a green branch)",pos:"intj",gender:null,note:"Green branches are alive and growing.\nBeing stuck on a dead branch means stagnation.",example:"A: Er kommt einfach auf keinen gruenen Zweig.\nB: Ja, nichts klappt bei ihm.\nA: Vielleicht braucht er Hilfe.\nB: Oder eine neue Strategie.",exampleSrc:"A: He simply never prospers.\nB: Yes, nothing works for him.\nA: Maybe he needs help.\nB: Or a new strategy.",funFact:"Green branches are alive and growing. Being stuck on a dead branch means stagnation. Old German imagery from forestry. 'Auf keinen gruenen Zweig kommen' means to never succeed or prosper."},
{type:"teach",trg:"Den Wald vor lauter Baeumen nicht sehen",src:"to not see the forest for the trees",pos:"intj",gender:null,note:"Missing the big picture because of too many details.\nNearly identical in English and German.",example:"A: Ich verstehe die einzelnen Wörter, aber nicht den Satz.\nB: Du siehst den Wald vor lauter Baeumen nicht.\nA: Genau! Zu viele Details.\nB: Tritt einen Schritt zurück.",exampleSrc:"A: I understand the individual words but not the sentence.\nB: You cannot see the forest for the trees.\nA: Exactly! Too many details.\nB: Take a step back.",funFact:"Perspective lost in complexity. The German version is nearly identical to the English one. Universal wisdom about the danger of losing the big picture in a sea of details."},
{type:"mc",q:"Jemand sieht das grosse Ganze nicht, weil zu viele Details im Weg sind. Welche Redewendung passt?",opts:["Den Wald vor lauter Baeumen nicht sehen","Auf keinen gruenen Zweig kommen","Eulen nach Athen tragen","Ins Fettnaepfchen treten"],ans:"Den Wald vor lauter Baeumen nicht sehen",hint:"Missing the big picture because of too many small things. A forest idiom about perspective."},
{type:"teach",trg:"Eulen nach Athen tragen",src:"to carry coals to Newcastle (lit: to carry owls to Athens)",pos:"intj",gender:null,note:"Doing something pointless because it already exists in abundance.\nAthens's symbol was the owl.",example:"A: Soll ich ihm Tipps zum Backen geben?\nB: Das wäre Eulen nach Athen tragen!\nA: Stimmt, er ist ja Baeckermeister.\nB: Genau. Er braucht keine Backtipps.",exampleSrc:"A: Should I give him tips on baking?\nB: That would be carrying owls to Athens!\nA: True, he is a master baker.\nB: Exactly. He does not need baking tips.",funFact:"Athens's symbol was the owl (on coins, in art). Bringing more owls to Athens is pointless. Like bringing sand to the Sahara. The German idiom dates back to ancient references."},
{type:"teach",trg:"Jemandem Honig ums Maul schmieren",src:"to flatter, to butter someone up (lit: to smear honey around someone's mouth)",pos:"intj",gender:null,note:"Insincere praise. Sticky sweetness applied to win favor.\n'Er schmiert ihr Honig ums Maul.'",example:"A: Du bist der beste Koch der Welt!\nB: Schmier mir keinen Honig ums Maul.\nA: Ich meine es ernst!\nB: Trotzdem. Ehrlichkeit ist besser als Honig.",exampleSrc:"A: You are the best cook in the world!\nB: Do not smear honey around my mouth.\nA: I mean it!\nB: Still. Honesty is better than honey.",funFact:"Sticky sweetness applied to make someone feel good. Insincere praise. 'Er schmiert ihr Honig ums Maul' = He is flattering her. The honey-mouth image is vivid and unforgettable."},
{type:"teach",trg:"Schmetterlinge im Bauch haben",src:"to have butterflies in your stomach",pos:"intj",gender:null,note:"Being nervously in love or excited.\nSame image as in English.",example:"A: Hast du Schmetterlinge im Bauch?\nB: Ja, tausend Stück!\nA: Das ist ein gutes Zeichen.\nB: Oder ein Zeichen, dass ich nervoes bin.",exampleSrc:"A: Do you have butterflies in your stomach?\nB: Yes, a thousand of them!\nA: That is a good sign.\nB: Or a sign that I am nervous.",funFact:"The fluttering feeling of nervous excitement. Same image as English 'butterflies in your stomach.' Verumius knows this feeling from his first day in Germany. Love and anxiety share the same butterflies."},
{type:"teach",trg:"Das Kind mit dem Bade ausschütten",src:"to throw the baby out with the bathwater",pos:"intj",gender:null,note:"Discarding something valuable along with what is unwanted.\nMedieval origin: shared bathwater.",example:"A: Ich will alles ändern!\nB: Pass auf, dass du das Kind nicht mit dem Bade ausschüttest.\nA: Du meinst, ich soll das Gute behalten?\nB: Genau. Nicht alles wegwerfen.",exampleSrc:"A: I want to change everything!\nB: Be careful not to throw the baby out with the bathwater.\nA: You mean I should keep the good parts?\nB: Exactly. Do not throw everything away.",funFact:"Medieval origin: the whole family shared one bath. The baby bathed last in dirty water. Careful what you throw away! A warning against destroying the good while removing the bad."},
{type:"teach",trg:"Sich aus dem Staub machen",src:"to sneak away (lit: to make oneself out of the dust)",pos:"intj",gender:null,note:"Disappearing quietly, often to avoid responsibility.\n'Er hat sich aus dem Staub gemacht.'",example:"A: Wo ist er hin?\nB: Er hat sich aus dem Staub gemacht.\nA: Einfach so? Ohne ein Wort?\nB: Ja, verschwunden wie Staub im Wind.",exampleSrc:"A: Where did he go?\nB: He sneaked away.\nA: Just like that? Without a word?\nB: Yes, vanished like dust in the wind.",funFact:"Disappearing like dust in the wind. Gone without a trace. Often used for people avoiding responsibility. 'Er hat sich aus dem Staub gemacht' implies a deliberate, quiet departure."},
{type:"fb",s:"Er hat {1} aus dem Staub gemacht. Er ist einfach verschwunden.",a:["sich"],opts:["sich","sie","ihn","uns"],hint:"This idiom is reflexive. The person makes THEMSELVES out of the dust. Sneaking away quietly.",sSrc:"He sneaked away. He simply vanished."},
{type:"teach",trg:"Auf dem Holzweg sein",src:"to be on the wrong track (lit: to be on the wood path)",pos:"intj",gender:null,note:"A Holzweg leads only to a logging site, not a destination.\n'Da bist du auf dem Holzweg!'",example:"A: Ich glaube, das Wort bedeutet 'Fisch.'\nB: Da bist du auf dem Holzweg!\nA: Wirklich? Was bedeutet es dann?\nB: Etwas ganz anderes. Versuch nochmal.",exampleSrc:"A: I think the word means 'fish.'\nB: You are on the wrong track!\nA: Really? What does it mean then?\nB: Something completely different. Try again.",funFact:"A Holzweg is a path that leads only to a logging site, not a destination. Following it means you end up nowhere. 'Da bist du auf dem Holzweg!' = You are mistaken! Forest paths that deceive."},
{type:"teach",trg:"Tomaten auf den Augen haben",src:"to be oblivious (lit: to have tomatoes on your eyes)",pos:"intj",gender:null,note:"Not seeing what is right in front of you.\n'Hast du Tomaten auf den Augen?'",example:"A: Ich sehe das Schild nicht.\nB: Hast du Tomaten auf den Augen?\nA: Wo ist es denn?\nB: Direkt vor dir! Grosse rote Buchstaben!",exampleSrc:"A: I cannot see the sign.\nB: Do you have tomatoes on your eyes?\nA: Where is it then?\nB: Right in front of you! Big red letters!",funFact:"Red tomatoes blocking your vision. Used when someone misses the obvious. 'Hast du Tomaten auf den Augen?' = Are you blind? A uniquely German image for obliviousness."},
{type:"teach",trg:"das Fettnäpfchen",src:"the little grease pot",pos:"noun",gender:"n",note:"Neuter noun. 'Fett' (fat/grease) + 'Naepfchen' (little pot).\nSource of the idiom 'ins Fettnäpfchen treten.'",example:"A: Was ist ein Fettnäpfchen?\nB: Ein kleines Toepfchen mit Fett, früher an der Tuer.\nA: Und wenn man hineintritt?\nB: Dann hat man einen Fehler gemacht!",exampleSrc:"A: What is a Fettnäpfchen?\nB: A small pot with grease, formerly by the door.\nA: And when you step in it?\nB: Then you have made a mistake!",funFact:"A small container of grease kept by the door of old German houses. The diminutive '-naepfchen' makes it neuter. Stepping in it was a social metaphor for clumsiness that survives in modern German."},
{type:"match",pairs:[{trg:"Jemandem die Daumen drücken",src:"to wish someone luck"},{trg:"Auf dem Holzweg sein",src:"to be on the wrong track"},{trg:"Schmetterlinge im Bauch haben",src:"to have butterflies in your stomach"},{trg:"Eulen nach Athen tragen",src:"to do something pointless"}]},
{type:"mc",q:"Was bedeutet 'Sich aus dem Staub machen'?",opts:["to give up something important","to sneak away quietly","to tidy up and clean the dust","to make a careless mistake"],ans:"to sneak away quietly",hint:"Think of someone vanishing without a sound, like dust dispersed by the wind, often to escape responsibility."}
]},

// --- Lesson: Sprichwoerter verstehen ---
{id:"deu_r28l8",title:"Sprichwoerter verstehen",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Sprichwoerter verstehen",desc:"Understand and explain German idioms. Describe their meanings, origins, and how they reflect German culture and values.",goals:["Learn verbs for describing and explaining","Understand how idioms are transmitted","Use metaphorical language in context"]},
{type:"teach",trg:"beschreiben",src:"to describe",pos:"verb",gender:null,note:"'Be-' + 'schreiben' (to write). Not separable.\nStrong verb: beschreiben/beschrieb/beschrieben.",example:"A: Kannst du die Backstube beschreiben?\nB: Heinrich beschrieb sie als warm und voller Mehl.\nA: Wie hat er sie genau beschrieben?\nB: Mit vielen bildlichen Ausdrücken.",exampleSrc:"A: Can you describe the bakery?\nB: Heinrich described it as warm and full of flour.\nA: How did he describe it exactly?\nB: With many figurative expressions.",funFact:"'Be-' + 'schreiben' (to write). Covering something with writing (words). Not separable. Strong verb: beschreiben/beschrieb/beschrieben. 'Beschreibung' = description."},
{type:"teach",trg:"auslegen",src:"to interpret, to lay out",pos:"verb",gender:null,note:"'Aus' (out) + 'legen' (to lay). Separable.\n'Wie legen Sie dieses Sprichwort aus?'",example:"A: Wie legst du dieses Sprichwort aus?\nB: Ich lege es so aus: Geduld ist wichtig.\nA: Kann man es auch anders auslegen?\nB: Ja, jeder legt Sprichwörter anders aus.",exampleSrc:"A: How do you interpret this proverb?\nB: I interpret it this way: patience is important.\nA: Can you interpret it differently too?\nB: Yes, everyone interprets proverbs differently.",funFact:"Separable: 'Wie legen Sie dieses Sprichwort aus?' Interpretation: laying out the possible meanings. 'Auslegung' = interpretation. Also: to display goods in a shop."},
{type:"teach",trg:"verdeutlichen",src:"to clarify, to make clear",pos:"verb",gender:null,note:"'Ver-' + 'deutlich' (clear) + '-en.' Not separable.\nStronger than 'erklären.'",example:"A: Kannst du das verdeutlichen?\nB: Ja, ich verdeutliche es mit einem Beispiel.\nA: Das verdeutlicht die Sache.\nB: Gut. Klarheit ist das Ziel.",exampleSrc:"A: Can you clarify that?\nB: Yes, I will clarify it with an example.\nA: That clarifies the matter.\nB: Good. Clarity is the goal.",funFact:"Making something 'deutlich' (clear). Stronger than 'erklären' (to explain). Not separable. 'Können Sie das verdeutlichen?' is a polite request for more clarity. 'Verdeutlichung' = clarification."},
{type:"teach",trg:"widerspiegeln",src:"to reflect, to mirror",pos:"verb",gender:null,note:"'Wider' (against/back) + 'spiegeln' (to mirror).\n'Sprichwörter spiegeln die Kultur wider.'",example:"A: Was spiegeln Sprichwörter wider?\nB: Sie spiegeln die Werte einer Kultur wider.\nA: Und Heinrichs Geschichten?\nB: Die spiegeln sein ganzes Leben wider.",exampleSrc:"A: What do proverbs reflect?\nB: They reflect the values of a culture.\nA: And Heinrich's stories?\nB: They reflect his entire life.",funFact:"Culture reflected back like in a mirror. 'Wider' (against/back) + 'spiegeln' (to mirror). Separable: 'Sprichwörter spiegeln die Kultur wider.' 'Widerspiegelung' = reflection."},
{type:"teach",trg:"überliefern",src:"to hand down, to transmit through generations",pos:"verb",gender:null,note:"'Über' (over) + 'liefern' (to deliver). Not separable.\n'Mündlich überlieferte Weisheiten.'",example:"A: Wie wurden Sprichwörter überliefert?\nB: Mündlich, von Generation zu Generation.\nA: Niemand hat sie aufgeschrieben?\nB: Erst später. Vorher wurden sie nur überliefert.",exampleSrc:"A: How were proverbs handed down?\nB: Orally, from generation to generation.\nA: Nobody wrote them down?\nB: Only later. Before that they were just passed down.",funFact:"Delivering over time. 'Über' (over) + 'liefern' (to deliver). Not separable. 'Überlieferung' = tradition, transmission. How wisdom travels across centuries."},
{type:"fb",s:"Sprichwörter {1} die Werte und Traditionen einer Kultur.",a:["widerspiegeln"],opts:["widerspiegeln","verdeutlichen","beschreiben","auslegen"],hint:"Culture reflected back like in a mirror. 'Wider' (back) + 'spiegeln' (to mirror). Separable verb.",sSrc:"Proverbs reflect the values and traditions of a culture."},
{type:"teach",trg:"verbreiten",src:"to spread, to disseminate",pos:"verb",gender:null,note:"'Ver-' + 'breit' (broad/wide) + '-en.' Not separable.\n'Sprichwörter verbreiten Weisheit.'",example:"A: Wie verbreiten sich Sprichwörter?\nB: Durch Erzaehlen. Menschen verbreiten sie.\nA: Auch durch Buecher?\nB: Ja, aber die mündliche Verbreitung kam zuerst.",exampleSrc:"A: How do proverbs spread?\nB: Through telling. People spread them.\nA: Also through books?\nB: Yes, but oral dissemination came first.",funFact:"Making something wider. 'Ver-' + 'breit' (broad/wide). Not separable. 'Verbreitung' = dissemination. How wisdom travels from person to person, getting broader with each telling."},
{type:"teach",trg:"aufgreifen",src:"to take up, to pick up on",pos:"verb",gender:null,note:"'Auf' (up) + 'greifen' (to grab). Separable.\n'Er griff das Thema auf.'",example:"A: Verumius greift Heinrichs Sprichwörter auf.\nB: Ja, er greift sie auf und schreibt sie nieder.\nA: So werden sie bewahrt.\nB: Genau. Aufgreifen heißt bewahren.",exampleSrc:"A: Verumius picks up Heinrich's proverbs.\nB: Yes, he picks them up and writes them down.\nA: That way they are preserved.\nB: Exactly. To pick up means to preserve.",funFact:"Picking up a motif, a proverb, or an idea from someone else's words. Separable: 'Er griff das Thema auf.' Strong verb: aufgreifen/griff auf/aufgegriffen."},
{type:"teach",trg:"aussagen",src:"to state, to express",pos:"verb",gender:null,note:"'Aus' (out) + 'sagen' (to say). Separable.\n'Was sagt dieses Sprichwort aus?'",example:"A: Was sagt dieses Sprichwort aus?\nB: Es sagt aus, dass Geduld wichtig ist.\nA: Und was sagt Heinrichs Geschichte aus?\nB: Sie sagt aus, dass Tradition zaehlt.",exampleSrc:"A: What does this proverb express?\nB: It expresses that patience is important.\nA: And what does Heinrich's story express?\nB: It expresses that tradition counts.",funFact:"The meaning that comes OUT of the words. 'Aus' (out) + 'sagen' (to say). Separable: 'Was sagt dieses Sprichwort aus?' 'Aussage' = statement, meaning."},
{type:"mc",q:"Wenn jemand sagt 'Du bist auf dem Holzweg,' meint er...",opts:["Du liegst falsch, du bist auf dem falschen Weg","Du bist mitten im Wald verloren","Du baust gerade etwas auf","Du brauchst dringend mehr regelm\u00e4\u00dfige Bewegung"],ans:"Du liegst falsch, du bist auf dem falschen Weg",hint:"A Holz- path in the forest leads to a dead end. Following it means your direction is completely wrong."},
{type:"teach",trg:"lachen",src:"to laugh",pos:"verb",gender:null,note:"Regular verb. Ich lache, du lachst, er lacht.\n'Wer zuletzt lacht, lacht am besten.'",example:"A: Worüber lachst du?\nB: Über Heinrichs Geschichte. Er lacht selbst am meisten.\nA: Lachen ist gesund.\nB: Ja, und Sprichwörter, die zum Lachen bringen, bleiben haengen.",exampleSrc:"A: What are you laughing about?\nB: About Heinrich's story. He laughs most of all himself.\nA: Laughing is healthy.\nB: Yes, and proverbs that make you laugh stay with you.",funFact:"One of the most human actions there is. 'Das Lachen' (the laughter) is the nominalized form. Sprichwort: 'Wer zuletzt lacht, lacht am besten' (He who laughs last, laughs best). The Konjunktiv I form 'lache' appears in indirect speech reporting."},
{type:"fb",s:"Heinrich sagte, wer zuletzt lacht, {1} am besten.",a:["lache"],opts:["lache","lacht","lachte","gelacht"],hint:"The reported predicate needs Konjunktiv I, even when the wer-clause uses Indikativ. Apply the reporting mood to the main verb.",sSrc:"Heinrich said whoever laughs last laughs best."},
{type:"mc",q:"'Er tut, als ob er Tomaten auf den Augen hätte.' Das kombiniert...",opts:["als ob zusammen mit dem Indikativ","als ob + Konjunktiv II + Redewendung","Konjunktiv I f\u00fcr indirekte Rede","Einen ganz einfachen Vergleich nur mit wie"],ans:"als ob + Konjunktiv II + Redewendung",hint:"An unreal-comparison conjunction paired with subjunctive mood plus a fixed idiomatic expression. Three layers combined."},
{type:"teach",trg:"tragen",src:"to carry, to wear, to bear",pos:"verb",gender:null,note:"Strong verb. Ich trage, du trägst, er trägt.\nIrregular: a > ae in du/er forms.",example:"A: Was trägt Heinrich auf dem Arm?\nB: Eine alte Baeckerei in der Erinnerung.\nA: Wie trägt man eine Tradition weiter?\nB: Indem man sie erzählt.",exampleSrc:"A: What does Heinrich carry on his arm?\nB: An old bakery in memory.\nA: How does one carry on a tradition?\nB: By telling it.",funFact:"Strong verb with vowel change: tragen/trug/getragen. 'Eulen nach Athen tragen' (to carry owls to Athens) is a classic Redewendung meaning to do something pointless. The Konjunktiv I form 'trage' marks indirect speech."},
{type:"drag_fill",s:"Hildi bemerkte, ihr Vater {1} manchmal Eulen nach Athen.",blanks:{"1":"trage"},pool:["trage","trägt","truege","getragen","bringt","bringe"],hint:"Indirect speech requires the reporting mood. Select the form of 'tragen' that signals reported observation, not a direct factual statement.",sSrc:"Hildi remarked that her father sometimes carries owls to Athens."},
{type:"mc",q:"'Heinrich berichtete, er habe 40 Jahre gebacken. Er erzählte es, als wäre er noch jung. Er sagte, die Backstube sei seine Heimat.' Welche Konstrukte?",opts:["Nur Konjunktiv II in allen vorhandenen Formen","Nur Konjunktiv I in allen vorhandenen Formen","Konj. I Vergangenheit + als + Konj. II + Konj. I Gegenwart","Konj. I Vergangenheit + Konj. I Gegenwart + einfaches Konjunktiv II"],ans:"Konj. I Vergangenheit + als + Konj. II + Konj. I Gegenwart",hint:"Three sentences: the first reports a past action, the second makes an unreal comparison, the third reports a current state. Identify the mood in each."},
{type:"match",pairs:[{trg:"Ins Fettnäpfchen treten",src:"to make a social blunder"},{trg:"Sich aus dem Staub machen",src:"to sneak away"},{trg:"Schmetterlinge im Bauch haben",src:"to have butterflies"},{trg:"Eulen nach Athen tragen",src:"to do something pointless"}]},
{type:"fb",s:"Diese Geschichten wurden von Generation zu Generation {1}.",a:["überliefert"],opts:["überliefert","verbreitet","übertragen","umschrieben"],hint:"Handed down through time. The prefix 'über' (over) + 'liefern' (to deliver) creates this idea.",sSrc:"These stories were handed down from generation to generation."},
{type:"mc",q:"Soziale Medien helfen dabei, Nachrichten schnell zu...?",opts:["überliefern","umschreiben","begründen","verbreiten"],ans:"verbreiten",hint:"To spread or disseminate widely. Think of how news reaches many people at once."}]},
{id:"deu_r28l9",title:"Aufgeschrieben",icon:"\uD83D\uDCD3",xp:15,board:true,steps:[
{type:"intro",title:"Aufgeschrieben",desc:"The final proverbs and idioms. Review all constructs from Unit 28. Celebrate the meeting of oral tradition and foreign learner.",goals:["Master the remaining proverbs and idioms","Review all constructs from Unit 28","Celebrate the meeting of oral tradition and language learner"]},
{type:"teach",trg:"Zwei Fliegen mit einer Klappe schlagen",src:"to kill two birds with one stone (lit: to hit two flies with one swatter)",pos:"intj",gender:null,note:"Accomplishing two things at once.\nThe German version uses a fly swatter, not a stone.",example:"A: Ich gehe zum Supermarkt und hole die Post ab.\nB: Zwei Fliegen mit einer Klappe!\nA: Genau, warum zweimal gehen?\nB: Effizient. Sehr deutsch.",exampleSrc:"A: I am going to the supermarket and picking up the mail.\nB: Two flies with one swatter!\nA: Exactly, why go twice?\nB: Efficient. Very German.",funFact:"Same idea as English 'kill two birds with one stone,' but the German version is less violent: a fly swatter (Klappe) instead of a stone. Accomplishing two things at once. German efficiency in proverb form."},
{type:"teach",trg:"Die Katze im Sack kaufen",src:"to buy a pig in a poke (lit: to buy the cat in the bag)",pos:"intj",gender:null,note:"Buying something sight unseen.\nMedieval origin: dishonest merchants sold cats instead of rabbits.",example:"A: Ich kaufe das Auto ohne Probefahrt.\nB: Kauf nicht die Katze im Sack!\nA: Du meinst, ich soll es erst testen?\nB: Natürlich! Oeffne den Sack zuerst.",exampleSrc:"A: I am buying the car without a test drive.\nB: Do not buy the cat in the bag!\nA: You mean I should test it first?\nB: Of course! Open the bag first.",funFact:"Medieval origin: dishonest merchants sold cats instead of rabbits in closed bags. 'Pig in a poke' is the English equivalent. Trust but verify. Always open the bag before paying."},
{type:"teach",trg:"Was Haenschen nicht lernt, lernt Hans nimmermehr",src:"What you miss in childhood is hard to learn later",pos:"intj",gender:null,note:"Haenschen = little Hans (child). Hans = grown man.\nArgument for early education.",example:"A: Ich hätte früher Deutsch lernen sollen.\nB: Was Haenschen nicht lernt, lernt Hans nimmermehr!\nA: Aber ich lerne es doch jetzt!\nB: Stimmt. Du bist die Ausnahme!",exampleSrc:"A: I should have learned German earlier.\nB: What little Hans does not learn, big Hans never learns!\nA: But I am learning it now!\nB: True. You are the exception!",funFact:"Haenschen = little Hans (child). Hans = grown man. A German argument for early education. What the child misses, the adult cannot recover. Though Verumius proves that adults can learn too."},
{type:"teach",trg:"Wie man in den Wald hineinruft, so schallt es heraus",src:"You get what you give (lit: as one calls into the forest, so it echoes back)",pos:"intj",gender:null,note:"Treat people well and they treat you well.\nThe forest as mirror of behavior.",example:"A: Warum ist er so unfreundlich zu mir?\nB: Wie man in den Wald hineinruft, so schallt es heraus.\nA: Du meinst, weil ich zuerst unfreundlich war?\nB: Genau. Der Wald gibt zurück, was er empfängt.",exampleSrc:"A: Why is he so unfriendly to me?\nB: As you call into the forest, so it echoes back.\nA: You mean because I was unfriendly first?\nB: Exactly. The forest gives back what it receives.",funFact:"The forest as mirror of behavior. Action and reaction. Treat people well and they treat you well. The last proverb Verumius writes in his notebook. A fitting end: language learning echoes back what you put in."},
{type:"teach",trg:"bildlich gesprochen",src:"figuratively speaking",pos:"adv",gender:null,note:"Fixed phrase. 'Bildlich' (figuratively) + 'gesprochen' (spoken).\nAnnounces that what follows is not literal.",example:"A: Die Sprache ist eine Brücke.\nB: Bildlich gesprochen, ja.\nA: Natürlich bildlich gesprochen!\nB: Manchmal sind die besten Wahrheiten bildlich.",exampleSrc:"A: Language is a bridge.\nB: Figuratively speaking, yes.\nA: Of course figuratively speaking!\nB: Sometimes the best truths are figurative.",funFact:"The polite preface to a metaphor. 'Bildlich gesprochen ist die Sprache eine Brücke.' Signals to the listener: what follows is not literal but carries a deeper meaning through imagery."},
{type:"mc",q:"'Kauf nicht die Katze im Sack!' Was bedeutet das?",opts:["Kaufe nichts, ohne es vorher zu pruefen","Katzen gehoeren nicht in Saecke","Kaufe immer die billigste Option","Kaufe keine Katzen auf dem Markt"],ans:"Kaufe nichts, ohne es vorher zu pruefen",hint:"Medieval merchants sold cats instead of rabbits in closed bags. The proverb warns: inspect before you buy."},
{type:"teach",trg:"dem Vernehmen nach",src:"according to reports, reportedly",pos:"adv",gender:null,note:"Very formal. Newspaper register.\nAttributing without committing to the truth.",example:"A: Dem Vernehmen nach plant die Firma Veraenderungen.\nB: Wer sagt das?\nA: Ich habe es gehört. Dem Vernehmen nach.\nB: Also nur Geruechte. Noch nicht bestätigt.",exampleSrc:"A: According to reports, the company is planning changes.\nB: Who says that?\nA: I heard it. According to reports.\nB: So just rumors. Not yet confirmed.",funFact:"Very formal. 'Dem Vernehmen' (the hearing/perception) + 'nach' (according to). Newspaper register. Attributing a claim without committing to its truth. Distance through formality."},
{type:"teach",trg:"sozusagen",src:"so to speak",pos:"adv",gender:null,note:"'So' + 'zu' + 'sagen.' A softener for approximate language.\nConversational and versatile.",example:"A: Er ist sozusagen unser Sprichwort-Experte.\nB: Sozusagen? Also nicht offiziell?\nA: Nein, aber er weiß am meisten darüber.\nB: Dann ist er sozusagen der Beste.",exampleSrc:"A: He is, so to speak, our proverb expert.\nB: So to speak? So not officially?\nA: No, but he knows the most about it.\nB: Then he is, so to speak, the best.",funFact:"A softener that signals approximate or figurative language. 'Er ist sozusagen unser Experte' hedges the claim gently. Conversational and versatile. Three words joined into one adverb."},
{type:"teach",trg:"vermeintlich",src:"supposed, alleged",pos:"adj",gender:null,note:"'Ver-' + 'meintlich' (from 'meinen'). Casts doubt.\n'Der vermeintliche Experte' (the supposed expert).",example:"A: Der vermeintliche Experte lag falsch.\nB: Vermeintlich? Also kein echter Experte?\nA: Genau. Nur vermeintlich.\nB: Vermeintliches Wissen kann gefaehrlich sein.",exampleSrc:"A: The supposed expert was wrong.\nB: Supposed? So not a real expert?\nA: Exactly. Only supposedly.\nB: Supposed knowledge can be dangerous.",funFact:"Casts doubt: someone is thought to be something, but maybe is not. 'Der vermeintliche Experte' (the supposed expert). Polite skepticism. From 'meinen' (to think/suppose) with the doubting prefix 'ver-.'"},
{type:"teach",trg:"wörtlich genommen",src:"taken literally",pos:"adv",gender:null,note:"'Wörtlich' (literally) + 'genommen' (taken).\nThe opposite of 'bildlich gesprochen.'",example:"A: Wörtlich genommen heißt 'Morgenstund' die frühe Stunde.\nB: Aber bildlich gesprochen bedeutet es mehr.\nA: Genau. Wörtlich ist nur die Oberfläche.\nB: Die Tiefe liegt im übertragenen Sinn.",exampleSrc:"A: Taken literally, 'Morgenstund' means the early hour.\nB: But figuratively speaking it means more.\nA: Exactly. Literal is only the surface.\nB: The depth lies in the figurative sense.",funFact:"The opposite of 'bildlich gesprochen.' Surface meaning only. 'Wörtlich genommen bedeutet Morgenstund die frühe Stunde.' Understanding words at face value, without metaphorical interpretation."},
{type:"teach",trg:"als hätte",src:"as if (one) had",pos:"conj",gender:null,note:"'Als' + 'hätte' (Konjunktiv II of haben).\nShort form, more elegant than 'als ob er hätte.'",example:"A: Er erzählt es, als hätte er es gestern erlebt.\nB: Ja, als hätte er die Zeit angehalten.\nA: Die Erinnerung ist sehr lebendig.\nB: Als hätte sie nie aufgehört.",exampleSrc:"A: He tells it as if he had experienced it yesterday.\nB: Yes, as if he had stopped time.\nA: The memory is very vivid.\nB: As if it had never ended.",funFact:"The short 'als + Konjunktiv II' form. More elegant than 'als ob er gehabt hätte.' Literary register. 'Er erzählt es, als hätte er es gestern erlebt' compresses unreal comparison into three words."},
{type:"fb",s:"Er erzählt die Geschichte, {1} er sie gestern erlebt haette.",a:["als"],opts:["als","weil","obwohl","wenn"],hint:"The short form for unreal comparison. Just this word plus Konjunktiv II with inversion, no 'ob' needed.",sSrc:"He tells the story as if he had experienced it yesterday."},
{type:"mc",q:"'{blank} soll die Firma im naechsten Jahr expandieren.' Welcher Ausdruck passt?",opts:["Sozusagen","Dem Vernehmen nach","Bildlich gesprochen","Wörtlich genommen"],ans:"Dem Vernehmen nach",hint:"A formal phrase meaning 'according to reports.' Used when the source is unnamed or unofficial."}
]},
{id:"deu_r28l9b",title:"Aufgeschrieben (Teil 2)",icon:"\uD83D\uDCD3",xp:15,board:true,steps:[
{type:"intro",title:"Aufgeschrieben (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"sich beziehen auf",src:"to refer to",pos:"verb",gender:null,note:"Reflexive. Not separable. 'Das Sprichwort bezieht sich auf...'\nEssential for literary analysis.",example:"A: Worauf bezieht sich dieses Sprichwort?\nB: Es bezieht sich auf Geduld und Ausdauer.\nA: Und Heinrichs Geschichte?\nB: Die bezieht sich auf seine Jugend.",exampleSrc:"A: What does this proverb refer to?\nB: It refers to patience and perseverance.\nA: And Heinrich's story?\nB: That refers to his youth.",funFact:"Reflexive. Not separable. 'Das Sprichwort bezieht sich auf...' (The proverb refers to...). Essential for literary analysis. The 'auf' directs the reference to its target."},
{type:"teach",trg:"umschreiben",src:"to paraphrase, to describe in other words",pos:"verb",gender:null,note:"Not separable (stress on 'schreiben'). 'Um' (around) + 'schreiben' (to write).\n'Können Sie das umschreiben?'",example:"A: Können Sie das Sprichwort umschreiben?\nB: Ja: Wer geduldig ist, gewinnt am Ende.\nA: Das ist eine gute Umschreibung.\nB: Manchmal muss man Sprichwörter umschreiben.",exampleSrc:"A: Can you paraphrase the proverb?\nB: Yes: whoever is patient wins in the end.\nA: That is a good paraphrase.\nB: Sometimes you have to paraphrase proverbs.",funFact:"Saying the same thing in different words. 'Um' (around) + 'schreiben' (to write). Not separable when it means 'to paraphrase' (stress on schreiben). When separable (stress on um), it means 'to rewrite.'"},
{type:"teach",trg:"unterstellen",src:"to imply, to insinuate",pos:"verb",gender:null,note:"Not separable. 'Unter' (under) + 'stellen' (to place).\nPlacing a meaning underneath someone's words.",example:"A: Was wollen Sie mir unterstellen?\nB: Nichts! Ich unterstelle Ihnen gar nichts.\nA: Es klang aber so.\nB: Entschuldigung. Das war nicht meine Absicht.",exampleSrc:"A: What are you implying about me?\nB: Nothing! I am not implying anything.\nA: But it sounded that way.\nB: I am sorry. That was not my intention.",funFact:"Placing a meaning underneath someone's words. 'Was wollen Sie mir unterstellen?' (What are you implying about me?). Can be accusatory. Not separable. The hidden meaning placed 'under' the surface."},
{type:"teach",trg:"begründen",src:"to justify, to give reasons for",pos:"verb",gender:null,note:"'Be-' + 'gründen' (to found). Not separable.\nLaying the foundation (Grund) for an argument.",example:"A: Können Sie Ihre Meinung begründen?\nB: Ja, ich begründe sie mit Heinrichs Erfahrung.\nA: Das ist gut begründet.\nB: Eine Meinung ohne Begründung ist schwach.",exampleSrc:"A: Can you justify your opinion?\nB: Yes, I justify it with Heinrich's experience.\nA: That is well justified.\nB: An opinion without justification is weak.",funFact:"'Be-' + 'gründen' (to found). Laying the foundation (Grund = reason/ground) for an argument. Not separable. 'Begründung' = justification. In German academic culture, everything must be begründet."},
{type:"teach",trg:"entgegnen",src:"to reply, to retort",pos:"verb",gender:null,note:"'Ent-' + 'gegnen' (from 'gegen,' against). Not separable.\nMore confrontational than 'antworten.'",example:"A: Das ist falsch.\nB: Hildi entgegnete, es seien halb vier gewesen.\nA: Was hat Heinrich darauf entgegnet?\nB: Er entgegnete, das sei ein Detail.",exampleSrc:"A: That is wrong.\nB: Hildi retorted that it had been half past three.\nA: What did Heinrich reply to that?\nB: He retorted that it was a detail.",funFact:"A response that pushes back. More confrontational than 'antworten.' 'Ent-' + 'gegnen' (from 'gegen,' against). Formal debate register. Hildi's corrections are gentle Entgegnungen."},
{type:"mc",q:"Wenn jemand sagt 'Was wollen Sie mir unterstellen?', dann fuehlt er sich...",opts:["falsch beschuldigt oder verdaechtigt","gut beraten und informiert","amuesiert und unterhalten","gelobt und geschmeichelt"],ans:"falsch beschuldigt oder verdaechtigt",hint:"'Unterstellen' means to imply or insinuate something negative. The person feels accused.",sSrc:"If someone says 'What are you implying about me?', they feel falsely accused or suspected."},
{type:"teach",trg:"vermitteln",src:"to convey, to mediate",pos:"verb",gender:null,note:"'Ver-' + 'Mittel' (means/middle). Not separable.\n'Sprichwörter vermitteln Weisheit.'",example:"A: Was vermitteln Sprichwörter?\nB: Sie vermitteln Weisheit und Werte.\nA: Und Heinrich vermittelt sie an Verumius.\nB: Genau. Er ist der Vermittler zwischen den Generationen.",exampleSrc:"A: What do proverbs convey?\nB: They convey wisdom and values.\nA: And Heinrich conveys them to Verumius.\nB: Exactly. He is the mediator between generations.",funFact:"Placing something in the middle between sender and receiver. 'Ver-' + 'Mittel' (means/middle). Not separable. 'Vermittlung' = mediation, conveyance. Sprichwörter vermitteln Weisheit across time."},
{type:"teach",trg:"heissen",src:"to be called, to mean",pos:"verb",gender:null,note:"Strong verb: heissen/hiess/geheissen.\n'Was heißt das?' (What does that mean?). Abbreviation: d.h.",example:"A: Was heißt dieses Sprichwort?\nB: Es heißt, dass Geduld sich lohnt.\nA: Das heißt, ich soll warten?\nB: Das heißt, alles braucht seine Zeit.",exampleSrc:"A: What does this proverb mean?\nB: It means that patience pays off.\nA: That means I should wait?\nB: That means everything needs its time.",funFact:"The most basic word for 'to mean.' 'Was heißt das?' (What does that mean?). Strong verb: heissen/hiess/geheissen. 'Das heißt...' abbreviated as 'd.h.' is everywhere in German writing."},
{type:"tip",title:"Mündliche Tradition und der fremde Lerner",text:"Verumius, writing down Heinrich's proverbs, is capturing something real. Germany has a rich oral tradition: Märchen (Grimm), proverbs, idioms. They were passed down orally for centuries before anyone wrote them down. As a language learner, you are now part of this chain. When you learn a proverb, you carry it forward. Heinrich's stories exist because someone listened and someone wrote. Learning a language is cultural preservation.",deepDive:{title:"From voice to writing",text:"The Brothers Grimm collected fairy tales from storytellers and wrote them down. Before that, these stories existed only in people's voices. The same is true of proverbs: 'Morgenstund hat Gold im Mund' was said hundreds of times before anyone committed it to writing. Today, learners like Verumius preserve this tradition by listening, understanding, and passing it on."}},
{type:"mc",q:"'Was Haenschen nicht lernt, lernt Hans nimmermehr.' Dieses Sprichwort argumentiert, dass...",opts:["Hans leider niemals zur Schule gegangen ist","Was man in der Jugend verpasst, ist später schwer zu lernen","Kinder morgens viel schneller und leichter lernen","Der große Hans wird immer noch klüger als der kleine Hänschen"],ans:"Was man in der Jugend verpasst, ist später schwer zu lernen",hint:"Haenschen (little Hans) = childhood. Hans = adulthood. What the child misses, the adult cannot make up for."},
{type:"fb",s:"Heinrich erzählte, die alten Sprichwörter {1} zeitlos.",a:["seien"],opts:["seien","sind","waren","wären"],hint:"Konjunktiv I of 'sein' in indirect speech. Plural form because 'Sprichwörter' is plural.",sSrc:"Heinrich told that the old proverbs were timeless."},
{type:"mc",q:"'Hildi entgegnete, ihr Vater übertreibe manchmal. Er erzähle, als hätte er die Baeckerei noch. Sie fuegte hinzu, die Geschichten seien trotzdem wertvoll.' Wie viele Konstrukte?",opts:["Zwei Konjunktiv I und zwei Konjunktiv II zusammen","Alles nur Konjunktiv II","Drei Konjunktiv I + ein als + Konjunktiv II","Nur Konjunktiv I in allen Formen"],ans:"Drei Konjunktiv I + ein als + Konjunktiv II",hint:"Count the reporting mood forms in Hildi's three statements, then identify the one verb form that instead expresses an unreal scenario."},
{type:"teach",trg:"hineinrufen",src:"to call into (something)",pos:"verb",gender:null,note:"Hinein (into) + rufen (to call). Separable verb.\n'In den Wald hineinrufen' = to call into the forest.",example:"A: Warum rufst du in den Wald hinein?\nB: Ich teste, ob das Echo antwortet.\nA: Wer in den Wald hineinruft...\nB: ...bekommt es zurück. Das Sprichwort stimmt.",exampleSrc:"A: Why are you calling into the forest?\nB: I am testing whether the echo answers.\nA: Whoever calls into the forest...\nB: ...gets it back. The proverb is true.",funFact:"Hinein (into) + rufen (to call). Separable: 'Er ruft in den Wald hinein.' 'Wie man in den Wald hineinruft, so schallt es heraus' is one of Germany's most famous Sprichwörter: you get back what you put out. The Konjunktiv I form 'hineinrufe' signals indirect speech."},
{type:"drag_fill",s:"Heinrich sagte, wer in den Wald {1}, {2} es genauso zurück.",blanks:{"1":"hineinrufe","2":"bekomme"},pool:["hineinrufe","bekomme","hineinruft","bekommt","hineinriefe","bekaeme"],hint:"Both blanks report the proverb in indirect speech. Apply the reporting mood to both verbs: the wer-clause verb and the main predicate.",sSrc:"Heinrich said whoever calls into the forest gets it back the same way."},
{type:"match",pairs:[{trg:"Zwei Fliegen mit einer Klappe schlagen",src:"To kill two birds with one stone"},{trg:"Die Katze im Sack kaufen",src:"To buy a pig in a poke"},{trg:"Auf dem Holzweg sein",src:"To be on the wrong track"},{trg:"Tomaten auf den Augen haben",src:"To be oblivious"}]},
{type:"mc",q:"Was bedeutet 'sich beziehen auf'?",opts:["taken literally","to reply, to retort","figuratively speaking","to refer to"],ans:"to refer to",hint:"Reflexive verb with auf + accusative. Built from Beziehung (connection/link)."},
{type:"fb",s:"Können Sie das Sprichwort {1}?",a:["umschreiben"],opts:["bildlich gesprochen","wörtlich genommen","umschreiben","unterstellen"],hint:"um- (around) + schreiben (to write). To write around something = to rephrase it.",sSrc:"Can you paraphrase the proverb?"},
{type:"mc",q:"Was bedeutet 'begründen'?",opts:["to justify, to give reasons for","to buy a pig in a poke (lit: to buy the cat in the bag)","supposed, alleged","taken literally"],ans:"to justify, to give reasons for",hint:"From Grund (reason/ground). To provide the grounds or foundation for a claim."},
{type:"fb",s:"Wie sagt man 'to reply, to retort' auf Deutsch? {1}",a:["entgegnen"],opts:["entgegnen","vermeintlich","bildlich gesprochen","heissen"],hint:"From entgegen (against/toward). To speak back in response, often in disagreement.",sSrc:"How do you say 'to reply, to retort' in German?"},
{type:"mc",q:"Was bedeutet 'vermitteln'?",opts:["to kill two birds with one stone (lit: to hit two flies with one swatter)","to convey, to mediate","to buy a pig in a poke (lit: to buy the cat in the bag)","figuratively speaking"],ans:"to convey, to mediate",hint:"From Mitte (middle). To stand in the middle between two sides, bridging a gap."},
{type:"fb",s:"Wie sagt man 'to be called, to mean' auf Deutsch? {1}",a:["heissen"],opts:["sich beziehen auf","Was Haenschen nicht lernt, lernt Hans nimmermehr","heissen","Wie man in den Wald hineinruft, so schallt es heraus"],hint:"One of the first verbs any learner knows: 'Ich heisse...' (My name is...).",sSrc:"How do you say 'to be called, to mean' in German?"}
,{type:"match",pairs:[{trg:"die Erzählung",src:"narrative, story"},{trg:"die Metapher",src:"metaphor"},{trg:"poetisch",src:"poetic"},{trg:"zeitlos",src:"timeless"},{trg:"dichten",src:"to compose poetry, to write literary works"},{trg:"die Gattung",src:"genre, category"}]},{type:"match",pairs:[{trg:"das Werk",src:"work (of art/literature)"},{trg:"die Hauptfigur",src:"main character, protagonist"},{trg:"der Schauplatz",src:"setting, scene"},{trg:"der Kontext",src:"context"},{trg:"die Perspektive",src:"perspective, point of view"},{trg:"das Wortspiel",src:"pun, play on words"}]},{type:"match",pairs:[{trg:"angeblich",src:"allegedly, supposedly"},{trg:"die Erzählerin",src:"narrator (female)"},{trg:"die Nebenfigur",src:"secondary character"},{trg:"die Tragödie",src:"tragedy"},{trg:"wie wenn",src:"as if (informal)"},{trg:"existieren",src:"to exist"}]},{type:"match",pairs:[{trg:"schriftlich",src:"written, in writing"},{trg:"mitteilen",src:"to inform, to communicate"},{trg:"Es ist noch kein Meister vom Himmel gefallen",src:"Nobody is born an expert (lit: no master has yet fallen from the sky)"},{trg:"der Kopf",src:"the head"},{trg:"der Nagel",src:"the nail"},{trg:"Etwas auf den Nagel haengen",src:"to give up, to quit (lit: to hang something on a nail)"}]},{type:"match",pairs:[{trg:"Jemandem Honig ums Maul schmieren",src:"to flatter, to butter someone up (lit: to smear honey around someone's mouth)"},{trg:"Das Kind mit dem Bade ausschütten",src:"to throw the baby out with the bathwater"},{trg:"beschreiben",src:"to describe"},{trg:"auslegen",src:"to interpret, to lay out"},{trg:"verdeutlichen",src:"to clarify, to make clear"},{trg:"aufgreifen",src:"to take up, to pick up on"}]},{type:"match",pairs:[{trg:"aussagen",src:"to state, to express"},{trg:"vermeintlich",src:"supposed, alleged"},{trg:"unterstellen",src:"to imply, to insinuate"},{trg:"vermitteln",src:"to convey, to mediate"},{trg:"Was Haenschen nicht lernt, lernt Hans nimmermehr",src:"What you miss in childhood is hard to learn later"},{trg:"Wie man in den Wald hineinruft, so schallt es heraus",src:"You get what you give (lit: as one calls into the forest, so it echoes back)"},{trg:"hineinrufen",src:"to call into (something)"}]}]}
]};

export default UNIT_28;
